import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { AlertCircle, Check, X } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "sonner";

interface AIConfirmationProps {
  type: "task" | "goal" | "habit";
  data: any;
  onConfirm: () => Promise<void>;
  onCancel: () => void;
}

export default function AIConfirmation({ type, data, onConfirm, onCancel }: AIConfirmationProps) {
  const [isProcessing, setIsProcessing] = useState(false);
  const { user } = useAuth();

  const getTypeLabel = () => {
    switch (type) {
      case "task": return "tâche";
      case "goal": return "objectif";
      case "habit": return "habitude";
      default: return "élément";
    }
  };

  const handleConfirm = async () => {
    if (!user) return;

    setIsProcessing(true);
    try {
      // Créer l'élément dans la base de données selon le type
      let result;

      if (type === "task") {
        const { error } = await supabase
          .from('tasks')
          .insert({
            user_id: user.id,
            title: data.title,
            description: data.description || null,
            priority: data.priority || 'medium',
            due_date: data.due_date || null,
            completed: false
          });
        if (error) throw error;
        result = "Tâche créée avec succès !";
      } else if (type === "habit") {
        const { error } = await supabase
          .from('habits')
          .insert({
            user_id: user.id,
            title: data.title,
            description: data.description || null,
            frequency: data.frequency || 'daily',
            category: data.category || null,
            target: data.target || 1,
            streak: 0
          });
        if (error) throw error;
        result = "Habitude créée avec succès !";
      } else if (type === "goal") {
        const { error } = await supabase
          .from('goals')
          .insert({
            user_id: user.id,
            title: data.title,
            description: data.description || null,
            category: data.category || 'personal',
            target_date: data.target_date || null,
            progress: 0,
            completed: false
          });
        if (error) throw error;
        result = "Objectif créé avec succès !";
      }

      toast.success(result);
      await onConfirm();
    } catch (error) {
      console.error('Erreur lors de la création:', error);
      toast.error('Erreur lors de la création');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Card className="max-w-md mx-auto border-orange-200 bg-orange-50">
      <CardHeader className="pb-3">
        <CardTitle className="flex items-center gap-2 text-orange-800">
          <AlertCircle className="h-5 w-5" />
          Confirmation requise
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <p className="text-sm text-orange-700">
          L'assistant IA souhaite créer la {getTypeLabel()} suivante :
        </p>

        <div className="bg-white p-3 rounded-md border border-orange-200">
          <h4 className="font-medium text-gray-900">{data.title}</h4>
          {data.description && (
            <p className="text-sm text-gray-600 mt-1">{data.description}</p>
          )}
          {data.priority && (
            <p className="text-xs text-gray-500 mt-2">Priorité: {data.priority}</p>
          )}
          {data.frequency && (
            <p className="text-xs text-gray-500 mt-2">Fréquence: {data.frequency}</p>
          )}
          {data.category && (
            <p className="text-xs text-gray-500 mt-2">Catégorie: {data.category}</p>
          )}
        </div>

        <div className="flex gap-2 pt-2">
          <Button
            onClick={handleConfirm}
            disabled={isProcessing}
            className="flex-1 bg-green-600 hover:bg-green-700"
          >
            <Check className="h-4 w-4 mr-2" />
            {isProcessing ? "Création..." : "Confirmer"}
          </Button>
          <Button
            onClick={onCancel}
            variant="outline"
            disabled={isProcessing}
            className="flex-1"
          >
            <X className="h-4 w-4 mr-2" />
            Annuler
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState } from "react";
import { format } from "date-fns";
import { fr } from "date-fns/locale";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { X, Clock, Globe, Repeat, Users, Video, MapPin, List } from "lucide-react";
import { cn } from "@/lib/utils";

interface GoogleCalendarEventModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSave: (eventData: EventFormData) => void;
  initialData?: {
    date: Date;
    startTime?: string;
    endTime?: string;
  };
}

export interface EventFormData {
  title: string;
  type: "event" | "task" | "birthday";
  description: string;
  calendar: string;
  allDay: boolean;
  startDate: string;
  startTime: string;
  endDate: string;
  endTime: string;
  timezone: string;
  repeat: string;
  guests: string[];
  location: string;
  videoConference: boolean;
}

const eventTypes = [
  { value: "event", label: "Événement" },
  { value: "task", label: "Tâche" },
  { value: "birthday", label: "Anniversaire" },
];

const calendars = [
  { value: "mon-agenda", label: "Mon agenda", color: "bg-blue-500" },
  { value: "family", label: "Family", color: "bg-gray-500" },
];

const repeatOptions = [
  { value: "none", label: "Une seule fois" },
  { value: "daily", label: "Tous les jours" },
  { value: "weekly", label: "Toutes les semaines" },
  { value: "monthly", label: "Tous les mois" },
  { value: "yearly", label: "Tous les ans" },
];

export function GoogleCalendarEventModal({
  open,
  onOpenChange,
  onSave,
  initialData,
}: GoogleCalendarEventModalProps) {
  const [formData, setFormData] = useState<EventFormData>({
    title: "",
    type: "event",
    description: "",
    calendar: "mon-agenda",
    allDay: false,
    startDate: initialData?.date ? format(initialData.date, 'yyyy-MM-dd') : format(new Date(), 'yyyy-MM-dd'),
    startTime: initialData?.startTime || "13:00",
    endDate: initialData?.date ? format(initialData.date, 'yyyy-MM-dd') : format(new Date(), 'yyyy-MM-dd'),
    endTime: initialData?.endTime || "14:00",
    timezone: "Europe/Paris",
    repeat: "none",
    guests: [],
    location: "",
    videoConference: false,
  });

  const [showAdvanced, setShowAdvanced] = useState(false);

  const handleSave = () => {
    if (!formData.title.trim()) return;
    onSave(formData);
    onOpenChange(false);
  };

  const selectedCalendar = calendars.find(c => c.value === formData.calendar);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[550px] p-0 gap-0 max-h-[90vh] overflow-hidden flex flex-col">
        {/* Header */}
        <DialogHeader className="p-4 pb-3 border-b shrink-0">
          <div className="flex items-center justify-between">
            <DialogTitle className="text-xl font-normal">Ajouter un titre</DialogTitle>
            <div className="flex items-center gap-2">
              <Button
                onClick={handleSave}
                disabled={!formData.title.trim()}
                className="bg-[#f0c0c0] hover:bg-[#e0b0b0] text-gray-900"
              >
                Enregistrer
              </Button>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => onOpenChange(false)}
              >
                <X className="h-5 w-5" />
              </Button>
            </div>
          </div>
        </DialogHeader>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {/* Title */}
          <Input
            placeholder="Ajouter un titre"
            value={formData.title}
            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            className="border-0 border-b rounded-none text-lg px-0 focus-visible:ring-0"
          />

          {/* Event type tabs */}
          <div className="flex gap-2">
            {eventTypes.map((type) => (
              <Button
                key={type.value}
                variant={formData.type === type.value ? "default" : "outline"}
                size="sm"
                onClick={() => setFormData({ ...formData, type: type.value as any })}
                className={cn(
                  "rounded-full",
                  formData.type === type.value
                    ? "bg-gray-700 hover:bg-gray-600"
                    : "bg-gray-200 text-gray-900 hover:bg-gray-300 border-0"
                )}
              >
                {type.label}
              </Button>
            ))}
          </div>

          {/* Calendar selection */}
          <div className="flex items-center gap-3 py-2">
            <div className="flex items-center gap-2 flex-1">
              <div className={cn("w-3 h-3 rounded-full", selectedCalendar?.color)} />
              <span className="text-sm font-medium">{selectedCalendar?.label}</span>
            </div>
            <Select
              value={formData.calendar}
              onValueChange={(value) => setFormData({ ...formData, calendar: value })}
            >
              <SelectTrigger className="w-[180px] border-0 bg-transparent">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {calendars.map((cal) => (
                  <SelectItem key={cal.value} value={cal.value}>
                    <div className="flex items-center gap-2">
                      <div className={cn("w-3 h-3 rounded-full", cal.color)} />
                      {cal.label}
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* All day toggle */}
          <div className="flex items-center justify-between py-2">
            <div className="flex items-center gap-3">
              <Clock className="h-5 w-5 text-muted-foreground" />
              <span className="text-sm">Toute la journée</span>
            </div>
            <Switch
              checked={formData.allDay}
              onCheckedChange={(checked) => setFormData({ ...formData, allDay: checked })}
            />
          </div>

          {/* Date and time */}
          <div className="space-y-3">
            <div className="flex items-center gap-3">
              <Input
                type="date"
                value={formData.startDate}
                onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
                className="flex-1"
              />
              {!formData.allDay && (
                <Input
                  type="time"
                  value={formData.startTime}
                  onChange={(e) => setFormData({ ...formData, startTime: e.target.value })}
                  className="w-32"
                />
              )}
            </div>

            <div className="flex items-center gap-3">
              <Input
                type="date"
                value={formData.endDate}
                onChange={(e) => setFormData({ ...formData, endDate: e.target.value })}
                className="flex-1"
              />
              {!formData.allDay && (
                <Input
                  type="time"
                  value={formData.endTime}
                  onChange={(e) => setFormData({ ...formData, endTime: e.target.value })}
                  className="w-32"
                />
              )}
            </div>
          </div>

          {/* Timezone */}
          <div className="flex items-center gap-3 py-2 text-sm text-muted-foreground">
            <Globe className="h-5 w-5" />
            <span>heure normale d'Europe centrale</span>
          </div>

          {/* Repeat */}
          <div className="flex items-center gap-3 py-2">
            <Repeat className="h-5 w-5 text-muted-foreground" />
            <Select
              value={formData.repeat}
              onValueChange={(value) => setFormData({ ...formData, repeat: value })}
            >
              <SelectTrigger className="flex-1 border-0 bg-transparent h-auto p-0">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {repeatOptions.map((option) => (
                  <SelectItem key={option.value} value={option.value}>
                    {option.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Advanced options toggle */}
          {!showAdvanced && (
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowAdvanced(true)}
              className="w-full justify-start text-muted-foreground"
            >
              Ajouter une date limite
            </Button>
          )}

          {showAdvanced && (
            <>
              {/* Guests */}
              <div className="flex items-start gap-3 py-2">
                <Users className="h-5 w-5 text-muted-foreground mt-1" />
                <div className="flex-1">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="w-full justify-start text-muted-foreground h-auto p-0"
                  >
                    Ajouter des contacts
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    className="mt-2 text-xs"
                  >
                    Afficher les plannings
                  </Button>
                </div>
              </div>

              {/* Video conference */}
              <div className="flex items-center gap-3 py-2">
                <Video className="h-5 w-5 text-muted-foreground" />
                <Button
                  variant="ghost"
                  size="sm"
                  className="flex-1 justify-start text-muted-foreground h-auto p-0"
                >
                  Ajouter une visioconférence
                </Button>
              </div>

              {/* Location */}
              <div className="flex items-center gap-3 py-2">
                <MapPin className="h-5 w-5 text-muted-foreground" />
                <Button
                  variant="ghost"
                  size="sm"
                  className="flex-1 justify-start text-muted-foreground h-auto p-0"
                >
                  Ajouter un lieu
                </Button>
              </div>

              {/* Description */}
              <div className="flex items-start gap-3 py-2">
                <List className="h-5 w-5 text-muted-foreground mt-1" />
                <Button
                  variant="ghost"
                  size="sm"
                  className="flex-1 justify-start text-muted-foreground h-auto p-0"
                  onClick={() => {
                    const section = document.getElementById('description-section');
                    if (section) {
                      section.classList.toggle('hidden');
                    }
                  }}
                >
                  Ajouter des détails
                </Button>
              </div>

              <div id="description-section" className="hidden">
                <Textarea
                  placeholder="Description"
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  className="min-h-[80px]"
                />
              </div>
            </>
          )}

          {/* Task list section for tasks */}
          {formData.type === "task" && (
            <div className="flex items-center gap-3 py-2 border-t mt-4 pt-4">
              <List className="h-5 w-5 text-muted-foreground" />
              <span className="text-sm font-medium">Mes tâches</span>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import React from "react";

type MoodSummaryProps = {
  entries: { mood?: string }[];
  moods: { value: string; label: string; color: string }[];
};

const emojiByMood: Record<string, string> = {
  happy: "😊", sad: "😢", excited: "🤩", calm: "😌", stressed: "😰",
  grateful: "🙏", motivated: "💪", thoughtful: "🤔"
};

export default function JournalMoodSummary({ entries, moods }: MoodSummaryProps) {
  // Regroupe par humeur
  const moodCounts: Record<string, number> = {};
  entries.forEach(entry => {
    if (entry.mood) {
      moodCounts[entry.mood] = (moodCounts[entry.mood] ?? 0) + 1;
    }
  });

  return (
    <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 sm:gap-4 mb-3">
      {moods.map((mood) => {
        const count = moodCounts[mood.value] ?? 0;
        if (count === 0) return null;
        return (
          <Card
            key={mood.value}
            className="flex px-2 py-2 sm:p-4 items-center transition-shadow"
          >
            <CardContent className="p-0 flex items-center gap-2 sm:gap-4 w-full">
              <div className={`w-8 h-8 sm:w-12 sm:h-12 rounded-lg flex items-center justify-center ${mood.color}`}>
                <span className="text-xl sm:text-2xl">{emojiByMood[mood.value] || "📝"}</span>
              </div>
              <div className="flex flex-col gap-0.5 sm:gap-1">
                <div className="font-semibold text-xs sm:text-base">{mood.label}</div>
                <div className="text-[11px] sm:text-sm text-muted-foreground">
                  {count} entrée{count > 1 ? "s" : ""}
                </div>
              </div>
            </CardContent>
          </Card>
        );
      })}
      {/* Carte "Autres"/sans humeur ? */}
      {entries.filter(e => !e.mood).length > 0 && (
        <Card className="flex px-2 py-2 sm:p-4 items-center transition-shadow">
          <CardContent className="p-0 flex items-center gap-2 sm:gap-4 w-full">
            <div className="w-8 h-8 sm:w-12 sm:h-12 rounded-lg flex items-center justify-center bg-muted">
              <span className="text-xl sm:text-2xl">📝</span>
            </div>
            <div className="flex flex-col gap-0.5 sm:gap-1">
              <div className="font-semibold text-xs sm:text-base">Sans humeur</div>
              <div className="text-[11px] sm:text-sm text-muted-foreground">
                {entries.filter(e => !e.mood).length} entrée{entries.filter(e => !e.mood).length > 1 ? "s" : ""}
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import { Trash2, Plus, ChevronRight, ChevronDown, Edit2 } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { toast } from 'sonner';
import { SubobjectiveForm } from './SubobjectiveForm';

interface Subobjective {
  id: string;
  title: string;
  description?: string;
  completed: boolean;
  sort_order: number;
}

interface SubobjectiveListProps {
  goalId: string;
}

export const SubobjectiveList = ({ goalId }: SubobjectiveListProps) => {
  const { user } = useAuth();
  const [subobjectives, setSubobjectives] = useState<Subobjective[]>([]);
  const [isExpanded, setIsExpanded] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingSubobjective, setEditingSubobjective] = useState<Subobjective | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const fetchSubobjectives = async () => {
    if (!user) return;

    try {
      const { data, error } = await supabase
        .from('subobjectives')
        .select('*')
        .eq('parent_goal_id', goalId)
        .eq('user_id', user.id)
        .order('sort_order', { ascending: true });

      if (error) throw error;
      setSubobjectives(data || []);
    } catch (error) {
      console.error('Erreur lors du chargement des sous-objectifs:', error);
    }
  };

  useEffect(() => {
    fetchSubobjectives();
  }, [goalId, user]);

  const toggleCompletion = async (subobjectiveId: string, completed: boolean) => {
    if (!user) return;

    try {
      const { error } = await supabase
        .from('subobjectives')
        .update({ completed })
        .eq('id', subobjectiveId)
        .eq('user_id', user.id);

      if (error) throw error;

      setSubobjectives(prev =>
        prev.map(sub =>
          sub.id === subobjectiveId ? { ...sub, completed } : sub
        )
      );
    } catch (error) {
      console.error('Erreur lors de la mise à jour du sous-objectif:', error);
      toast.error('Erreur lors de la mise à jour');
    }
  };

  const deleteSubobjective = async (subobjectiveId: string) => {
    if (!user) return;

    try {
      const { error } = await supabase
        .from('subobjectives')
        .delete()
        .eq('id', subobjectiveId)
        .eq('user_id', user.id);

      if (error) throw error;

      setSubobjectives(prev => prev.filter(sub => sub.id !== subobjectiveId));
      toast.success('Sous-objectif supprimé');
    } catch (error) {
      console.error('Erreur lors de la suppression du sous-objectif:', error);
      toast.error('Erreur lors de la suppression');
    }
  };

  const handleEditSubobjective = (subobjective: Subobjective) => {
    setEditingSubobjective(subobjective);
    setShowForm(true);
  };

  const handleFormSuccess = () => {
    setShowForm(false);
    setEditingSubobjective(null);
    fetchSubobjectives();
  };

  const handleFormCancel = () => {
    setShowForm(false);
    setEditingSubobjective(null);
  };

  if (subobjectives.length === 0 && !showForm) {
    return (
      <Button
        variant="outline"
        size="sm"
        onClick={() => setShowForm(true)}
        className="mt-2 h-8 text-xs"
      >
        <Plus className="w-3 h-3 mr-1" />
        Ajouter un sous-objectif
      </Button>
    );
  }

  return (
    <div className="mt-3 space-y-2">
      <div className="flex items-center gap-2">
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setIsExpanded(!isExpanded)}
          className="h-6 w-6 p-0 hover:bg-accent"
        >
          {isExpanded ? (
            <ChevronDown className="w-3 h-3" />
          ) : (
            <ChevronRight className="w-3 h-3" />
          )}
        </Button>
        <span className="text-sm text-muted-foreground">
          {subobjectives.length} sous-objectif{subobjectives.length > 1 ? 's' : ''}
        </span>
        <Button
          variant="outline"
          size="sm"
          onClick={() => setShowForm(true)}
          className="h-6 w-6 p-0 ml-auto"
        >
          <Plus className="w-3 h-3" />
        </Button>
      </div>

      {showForm && (
        <SubobjectiveForm
          parentGoalId={goalId}
          onSuccess={handleFormSuccess}
          onCancel={handleFormCancel}
          initialSubobjective={editingSubobjective}
        />
      )}

      {isExpanded && (
        <div className="ml-4 space-y-2">
          {subobjectives.map((subobjective) => (
            <div
              key={subobjective.id}
              className="flex items-center gap-3 p-2 bg-muted/50 rounded-lg"
            >
              <Checkbox
                checked={subobjective.completed}
                onCheckedChange={(checked) =>
                  toggleCompletion(subobjective.id, checked as boolean)
                }
              />
              <div className="flex-1 min-w-0">
                <p className={`text-sm ${subobjective.completed ? 'line-through text-muted-foreground' : ''}`}>
                  {subobjective.title}
                </p>
                {subobjective.description && (
                  <p className="text-xs text-muted-foreground mt-1">
                    {subobjective.description}
                  </p>
                )}
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => handleEditSubobjective(subobjective)}
                className="h-6 w-6 p-0 hover:bg-accent"
              >
                <Edit2 className="w-3 h-3" />
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => deleteSubobjective(subobjective.id)}
                className="h-6 w-6 p-0 hover:bg-destructive/20"
              >
                <Trash2 className="w-3 h-3" />
              </Button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ChevronDown, ChevronRight, Plus, CheckSquare } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import React from "react";
import { SubtaskList } from "./SubtaskList";
import { ItemCard, FilterBar, ViewMode } from "@/components/shared/ItemCard";
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  DragEndEvent,
} from '@dnd-kit/core';
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  useSortable,
  rectSortingStrategy,
  verticalListSortingStrategy,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

type Task = {
  id: string;
  title: string;
  description?: string;
  completed: boolean;
  priority: "high" | "medium" | "low";
  due_date?: string;
  created_at?: string;
};

interface TaskListProps {
  tasks: Task[];
  loading?: boolean;
  onEdit: (task: Task) => void;
  onDelete: (id: string) => void;
  onToggleComplete: (id: string, completed: boolean) => void;
  subtasks?: { [taskId: string]: any[] };
  onRefreshSubtasks?: () => void;
  onReorder?: (tasks: Task[]) => void;
}

interface SortableTaskCardProps {
  task: Task;
  onEdit: (task: Task) => void;
  onDelete: (id: string) => void;
  onToggleComplete: (id: string, completed: boolean) => void;
  taskSubtasks: any[];
  isExpanded: boolean;
  onToggleExpanded: (taskId: string) => void;
  onRefreshSubtasks: () => void;
  viewMode: ViewMode;
}

function SortableTaskCard({
  task,
  onEdit,
  onDelete,
  onToggleComplete,
  taskSubtasks,
  isExpanded,
  onToggleExpanded,
  onRefreshSubtasks,
  viewMode,
}: SortableTaskCardProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: task.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  const completedSubtasks = taskSubtasks.filter(s => s.completed).length;

  return (
    <div ref={setNodeRef} style={style}>
      <ItemCard
        type="task"
        data={task}
        variant={isExpanded ? 'expanded' : 'standard'}
        onComplete={() => onToggleComplete(task.id, task.completed)}
        onEdit={() => onEdit(task)}
        onDelete={() => onDelete(task.id)}
        isDragging={isDragging}
        dragHandleProps={{ listeners, attributes }}
        subtaskCount={taskSubtasks.length}
        subtaskCompleted={completedSubtasks}
      >
        {/* Subtask toggle and list */}
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <button
              onClick={(e) => { e.stopPropagation(); e.preventDefault(); onToggleExpanded(task.id); }}
              className="flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition-colors"
            >
              {isExpanded ? (
                <ChevronDown className="h-4 w-4" />
              ) : (
                <ChevronRight className="h-4 w-4" />
              )}
              <span>{taskSubtasks.length} sous-tâche{taskSubtasks.length !== 1 ? 's' : ''}</span>
            </button>

            <Button
              variant="ghost"
              size="sm"
              onClick={(e) => {
                e.stopPropagation();
                if (!isExpanded) {
                  onToggleExpanded(task.id);
                }
              }}
              className="h-6 px-2 text-xs text-muted-foreground hover:text-foreground"
            >
              <Plus className="h-3 w-3 mr-1" />
              Ajouter
            </Button>
          </div>

          <AnimatePresence>
            {isExpanded && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.2 }}
              >
                <SubtaskList
                  taskId={task.id}
                  subtasks={taskSubtasks}
                  onRefresh={onRefreshSubtasks}
                />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </ItemCard>
    </div>
  );
}

export default function TaskList({
  tasks,
  loading,
  onEdit,
  onDelete,
  onToggleComplete,
  subtasks = {},
  onRefreshSubtasks = () => {},
  onReorder
}: TaskListProps) {
  const [expandedTasks, setExpandedTasks] = useState<Set<string>>(new Set());
  const [searchValue, setSearchValue] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('grid');
  const [priorityFilter, setPriorityFilter] = useState<'all' | 'high' | 'medium' | 'low'>('all');

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const toggleExpanded = (taskId: string) => {
    const newExpanded = new Set(expandedTasks);
    if (newExpanded.has(taskId)) {
      newExpanded.delete(taskId);
    } else {
      newExpanded.add(taskId);
    }
    setExpandedTasks(newExpanded);
  };

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;

    if (over && active.id !== over.id) {
      const oldIndex = filteredTasks.findIndex((t) => t.id === active.id);
      const newIndex = filteredTasks.findIndex((t) => t.id === over.id);
      const newTasks = arrayMove(tasks, oldIndex, newIndex);
      onReorder?.(newTasks);
    }
  };

  // Filter tasks
  const filteredTasks = tasks.filter(task => {
    const matchesSearch = task.title.toLowerCase().includes(searchValue.toLowerCase()) ||
      task.description?.toLowerCase().includes(searchValue.toLowerCase());
    const matchesPriority = priorityFilter === 'all' || task.priority === priorityFilter;
    return matchesSearch && matchesPriority;
  });

  if (loading) {
    return (
      <div className="space-y-4">
        <div className="h-10 bg-muted rounded animate-pulse" />
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {[1, 2, 3].map(i => (
            <Card key={i} className="animate-pulse">
              <CardContent className="p-4">
                <div className="flex items-center gap-4">
                  <div className="w-8 h-8 rounded-full bg-muted" />
                  <div className="flex-1 space-y-2">
                    <div className="h-4 bg-muted rounded w-2/3" />
                    <div className="h-3 bg-muted rounded w-1/3" />
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>
    );
  }

  if (tasks.length === 0) {
    return (
      <Card>
        <CardContent className="text-center py-12">
          <CheckSquare className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold mb-2">Aucune tâche</h3>
          <p className="text-muted-foreground">
            Commencez par créer votre première tâche !
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {/* Filter Bar */}
      <FilterBar
        searchValue={searchValue}
        onSearchChange={setSearchValue}
        viewMode={viewMode}
        onViewModeChange={setViewMode}
        priorityFilter={priorityFilter}
        onPriorityFilterChange={setPriorityFilter}
        showPriorityFilter
        showViewToggle
      />

      {/* Task Grid/List */}
      <DndContext
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={handleDragEnd}
      >
        <SortableContext 
          items={filteredTasks.map(t => t.id)} 
          strategy={viewMode === 'grid' ? rectSortingStrategy : verticalListSortingStrategy}
        >
          <motion.div 
            className={
              viewMode === 'grid' 
                ? "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3" 
                : "flex flex-col gap-3"
            }
          >
            <AnimatePresence mode="popLayout">
              {filteredTasks.map(task => (
                <SortableTaskCard
                  key={task.id}
                  task={task}
                  onEdit={onEdit}
                  onDelete={onDelete}
                  onToggleComplete={onToggleComplete}
                  taskSubtasks={subtasks[task.id] || []}
                  isExpanded={expandedTasks.has(task.id)}
                  onToggleExpanded={toggleExpanded}
                  onRefreshSubtasks={onRefreshSubtasks}
                  viewMode={viewMode}
                />
              ))}
            </AnimatePresence>
          </motion.div>
        </SortableContext>
      </DndContext>

      {/* Empty filtered state */}
      {filteredTasks.length === 0 && tasks.length > 0 && (
        <Card>
          <CardContent className="text-center py-8">
            <p className="text-muted-foreground">
              Aucune tâche ne correspond à vos filtres.
            </p>
            <Button 
              variant="link" 
              onClick={() => {
                setSearchValue('');
                setPriorityFilter('all');
              }}
            >
              Réinitialiser les filtres
            </Button>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useLifeWheelData } from "@/hooks/useLifeWheelData";
import { motion } from "framer-motion";
import { Compass, Loader2 } from "lucide-react";
import {
  ResponsiveContainer,
  RadarChart,
  PolarGrid,
  PolarAngleAxis,
  PolarRadiusAxis,
  Radar,
  Tooltip
} from "recharts";

export function LifeWheelChart() {
  const { data, isLoading } = useLifeWheelData();

  if (isLoading) {
    return (
      <Card>
        <CardContent className="py-12 flex items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </CardContent>
      </Card>
    );
  }

  const chartData = data?.data || [];
  const balance = data?.balance || 0;

  const getBalanceInfo = (balance: number) => {
    if (balance >= 80) return { label: 'Excellent équilibre', color: 'bg-green-500' };
    if (balance >= 60) return { label: 'Bon équilibre', color: 'bg-blue-500' };
    if (balance >= 40) return { label: 'À améliorer', color: 'bg-yellow-500' };
    return { label: 'Déséquilibré', color: 'bg-orange-500' };
  };

  const balanceInfo = getBalanceInfo(balance);

  // Find weakest and strongest categories
  const sorted = [...chartData].sort((a, b) => b.score - a.score);
  const strongest = sorted[0];
  const weakest = sorted[sorted.length - 1];

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.2 }}
    >
      <Card>
        <CardHeader className="pb-2">
          <div className="flex items-center justify-between">
            <CardTitle className="text-base flex items-center gap-2">
              <Compass className="h-4 w-4 text-primary" />
              Roue de la Vie
            </CardTitle>
            <Badge className={`${balanceInfo.color} text-white`}>
              {balanceInfo.label}
            </Badge>
          </div>
        </CardHeader>
        <CardContent>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <RadarChart cx="50%" cy="50%" outerRadius="70%" data={chartData}>
                <PolarGrid stroke="hsl(var(--border))" />
                <PolarAngleAxis 
                  dataKey="category" 
                  tick={{ 
                    fontSize: 11, 
                    fill: 'hsl(var(--muted-foreground))' 
                  }}
                />
                <PolarRadiusAxis 
                  angle={30} 
                  domain={[0, 100]} 
                  tick={{ fontSize: 10 }}
                  tickCount={5}
                />
                <Radar
                  name="Score"
                  dataKey="score"
                  stroke="hsl(var(--primary))"
                  fill="hsl(var(--primary))"
                  fillOpacity={0.3}
                  strokeWidth={2}
                />
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'hsl(var(--background))',
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px',
                    fontSize: '12px'
                  }}
                  formatter={(value: number, name: string, props: any) => [
                    <div key="tooltip" className="space-y-1">
                      <div className="font-medium">{value}%</div>
                      <div className="text-xs text-muted-foreground">
                        {props.payload.habits} habitudes • {props.payload.goals} objectifs
                      </div>
                    </div>,
                    props.payload.category
                  ]}
                />
              </RadarChart>
            </ResponsiveContainer>
          </div>

          {/* Insights */}
          <div className="grid grid-cols-2 gap-3 mt-4">
            {strongest && strongest.score > 0 && (
              <div className="p-3 bg-green-500/10 rounded-lg border border-green-500/20">
                <p className="text-xs text-muted-foreground">Point fort</p>
                <p className="font-medium text-green-600 dark:text-green-400">
                  {strongest.category} ({strongest.score}%)
                </p>
              </div>
            )}
            {weakest && weakest.score < 100 && (
              <div className="p-3 bg-orange-500/10 rounded-lg border border-orange-500/20">
                <p className="text-xs text-muted-foreground">À développer</p>
                <p className="font-medium text-orange-600 dark:text-orange-400">
                  {weakest.category} ({weakest.score}%)
                </p>
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useAnalyticsData } from "@/hooks/useAnalyticsData";
import { useAuth } from "@/hooks/useAuth";
import { useSubscription } from "@/hooks/useSubscription";
import { supabase } from "@/integrations/supabase/client";
import { Brain, FileText, Loader2, RefreshCw, Calendar, TrendingUp, Award, Crown, Lock, Save, Check } from "lucide-react";
import { Markdown } from "@/components/Markdown";
import { toast } from "sonner";
import { motion } from "framer-motion";
import { Link } from "react-router-dom";

export const MonthlyAIReport = () => {
  const { user } = useAuth();
  const { isPremium, canUseFeature, getRemainingUses, trackUsage } = useSubscription();
  const { taskCompletionRate, totalFocusTime, streakCount, habitsData, tasksData } = useAnalyticsData();
  const [report, setReport] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaved, setIsSaved] = useState(false);

  // Load saved report on mount
  useEffect(() => {
    const loadSavedReport = async () => {
      if (!user) return;

      const now = new Date();
      const monthKey = `${now.getFullYear()}-${now.getMonth()}`;

      const { data } = await supabase
        .from('ai_productivity_analysis')
        .select('analysis_data')
        .eq('user_id', user.id)
        .maybeSingle();

      if (data?.analysis_data) {
        const savedData = data.analysis_data as { report: string; monthKey: string };
        if (savedData.monthKey === monthKey) {
          setReport(savedData.report);
          setIsSaved(true);
        }
      }
    };

    loadSavedReport();
  }, [user]);

  const saveReport = async () => {
    if (!user || !report) return;

    const now = new Date();
    const monthKey = `${now.getFullYear()}-${now.getMonth()}`;

    const { error } = await supabase
      .from('ai_productivity_analysis')
      .upsert({
        user_id: user.id,
        analysis_data: { report, monthKey, savedAt: new Date().toISOString() }
      }, { onConflict: 'user_id' });

    if (error) {
      toast.error("Erreur lors de la sauvegarde");
    } else {
      setIsSaved(true);
      toast.success("Rapport sauvegardé !");
    }
  };

  const generateReport = async () => {
    if (!user) return;

    if (!isPremium && !canUseFeature("analysis")) {
      toast.error("Limite quotidienne atteinte. Passez à Premium pour plus d'analyses !");
      return;
    }

    setIsGenerating(true);
    setIsSaved(false);

    try {
      const now = new Date();
      const startOfPrevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      const endOfPrevMonth = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59, 999);

      const [tasksResult, habitsResult, focusResult, journalResult, goalsResult] = await Promise.all([
        supabase.from('tasks').select('*').eq('user_id', user.id).gte('created_at', startOfPrevMonth.toISOString()).lte('created_at', endOfPrevMonth.toISOString()),
        supabase.from('habits').select('*').eq('user_id', user.id),
        supabase.from('focus_sessions').select('*').eq('user_id', user.id).gte('created_at', startOfPrevMonth.toISOString()).lte('created_at', endOfPrevMonth.toISOString()),
        supabase.from('journal_entries').select('*').eq('user_id', user.id).gte('created_at', startOfPrevMonth.toISOString()).lte('created_at', endOfPrevMonth.toISOString()),
        supabase.from('goals').select('*').eq('user_id', user.id),
      ]);

      const monthlyData = {
        tasks: { total: tasksResult.data?.length || 0, completed: tasksResult.data?.filter(t => t.completed).length || 0 },
        habits: { total: habitsResult.data?.length || 0, avgStreak: habitsResult.data?.reduce((sum, h) => sum + (h.streak || 0), 0) / (habitsResult.data?.length || 1) },
        focus: { sessions: focusResult.data?.length || 0, totalMinutes: focusResult.data?.reduce((sum, s) => sum + (s.duration || 0), 0) || 0 },
        journal: { entries: journalResult.data?.length || 0 },
        goals: { total: goalsResult.data?.length || 0, completed: goalsResult.data?.filter(g => g.completed).length || 0, avgProgress: goalsResult.data?.reduce((sum, g) => sum + (g.progress || 0), 0) / (goalsResult.data?.length || 1) },
      };

      const { data, error } = await supabase.functions.invoke('gemini-chat-enhanced', {
        body: {
          message: `Génère un rapport mensuel CONCIS (max 300 mots) avec:
1. **Score** - Note /100
2. **Résumé** - 2 phrases max
3. **Top 3** - Points forts (1 ligne chacun)
4. **À améliorer** - 2 axes (1 ligne chacun)
5. **Action** - 1 conseil prioritaire

Données ${startOfPrevMonth.toLocaleDateString('fr-FR', { month: 'long' })}:
Tâches: ${monthlyData.tasks.completed}/${monthlyData.tasks.total} | Focus: ${Math.round(monthlyData.focus.totalMinutes / 60)}h | Objectifs: ${monthlyData.goals.completed}/${monthlyData.goals.total}`,
          context: { analysis_mode: true, user_data: monthlyData }
        }
      });

      if (error) throw error;
      if (!isPremium) trackUsage("analysis");

      setReport(data.response);
      toast.success("Rapport généré !");
    } catch (error: any) {
      console.error("Error:", error);
      toast.error("Erreur lors de la génération");
    } finally {
      setIsGenerating(false);
    }
  };

  const previousMonth = new Date(new Date().getFullYear(), new Date().getMonth() - 1, 1).toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
    >
      <Card className="dashboard-card overflow-hidden">
        <CardHeader className="pb-3">
          <CardTitle className="flex items-center justify-between flex-wrap gap-2">
            <div className="flex items-center gap-2">
              <div className="p-2 rounded-lg bg-gradient-to-br from-primary/20 to-purple-500/20">
                <FileText className="h-5 w-5 text-primary" />
              </div>
              <div>
                <span className="font-heading">Rapport Mensuel IA</span>
                <Badge variant="outline" className="ml-2 text-xs capitalize">
                  {previousMonth}
                </Badge>
              </div>
            </div>
            <div className="flex items-center gap-2">
              {!isPremium && (
                <Badge variant="outline" className="text-xs">
                  {getRemainingUses("analysis")}/1 restant
                </Badge>
              )}
              {report && !isSaved && (
                <Button onClick={saveReport} variant="outline" size="sm" className="gap-2">
                  <Save className="h-4 w-4" />
                  Sauvegarder
                </Button>
              )}
              {isSaved && (
                <Badge variant="secondary" className="text-xs gap-1">
                  <Check className="h-3 w-3" /> Sauvegardé
                </Badge>
              )}
              <Button
                onClick={generateReport}
                disabled={isGenerating || (!isPremium && !canUseFeature("analysis"))}
                size="sm"
                className="gap-2"
              >
                {isGenerating ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin" />
                    ...
                  </>
                ) : report ? (
                  <>
                    <RefreshCw className="h-4 w-4" />
                    Nouveau
                  </>
                ) : (
                  <>
                    <Brain className="h-4 w-4" />
                    Générer
                  </>
                )}
              </Button>
            </div>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {!isPremium && !canUseFeature("analysis") && !report ? (
            <div className="text-center py-8 space-y-4">
              <Lock className="h-12 w-12 mx-auto text-muted-foreground" />
              <div>
                <h4 className="font-semibold">Limite quotidienne atteinte</h4>
                <p className="text-sm text-muted-foreground">
                  Passez à Premium pour des rapports illimités
                </p>
              </div>
              <Button asChild size="sm">
                <Link to="/settings">
                  <Crown className="h-4 w-4 mr-2" />
                  Passer à Premium
                </Link>
              </Button>
            </div>
          ) : report ? (
            <div className="prose prose-sm dark:prose-invert max-w-none">
              <Markdown content={report} />
            </div>
          ) : (
            <div className="text-center py-8 text-muted-foreground">
              <Brain className="h-12 w-12 mx-auto mb-4 opacity-50" />
              <p>Cliquez sur "Générer le rapport" pour obtenir une analyse IA complète de votre mois</p>
              <div className="flex justify-center gap-4 mt-4 text-xs">
                <div className="flex items-center gap-1">
                  <Calendar className="h-3 w-3" />
                  Vue d'ensemble
                </div>
                <div className="flex items-center gap-1">
                  <TrendingUp className="h-3 w-3" />
                  Tendances
                </div>
                <div className="flex items-center gap-1">
                  <Award className="h-3 w-3" />
                  Recommandations
                </div>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </motion.div>
  );
};

