    { icon: Settings, label: "Paramètres", path: "/settings" },
  ];

  const allNavItems = isAdmin 
    ? [...navItems, { icon: Shield, label: "Admin", path: "/admin" }]
    : navItems;

  const handleItemClick = (path: string) => {
    navigate(path);
    onItemClick?.();
  };

  return (
    <div className={cn("w-64 h-screen bg-card border-r border-border/40 sticky top-0 flex flex-col", className)}>
      {/* Logo */}
      <div className="p-4 border-b border-border/30">
        <div className="flex items-center gap-3">
          <img src={deepflowLogo} alt="DeepFlow Logo" className="h-9 w-9 rounded-xl object-contain bg-muted/50 p-1" />
          <h1 className="text-lg font-semibold tracking-tight text-foreground">DeepFlow</h1>
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 p-3 space-y-1 overflow-y-auto scrollbar-hidden">
        {allNavItems.map((item) => {
          const isActive = location.pathname === item.path;
          const isAdminItem = item.path === "/admin";
          return (
            <button
              key={item.path}
              className={cn(
                "w-full flex items-center gap-3 h-11 px-4 rounded-xl text-sm font-medium transition-colors duration-200",
                isActive 
                  ? "bg-primary/10 text-primary" 
                  : "text-muted-foreground hover:bg-muted/60 hover:text-foreground",
                isAdminItem && !isActive && "text-destructive hover:text-destructive hover:bg-destructive/10",
                "active:scale-[0.98]"
              )}
              onClick={() => handleItemClick(item.path)}
            >
              {/* Active indicator bar */}
              {isActive && (
                <div className="absolute left-0 w-[3px] h-6 rounded-r-full bg-primary" />
              )}
              {(item as any).isPenguin ? (
                <img src={penguinMascot} alt="" className="h-[18px] w-[18px] flex-shrink-0 object-contain" />
              ) : (
                <item.icon className={cn(
                  "h-[18px] w-[18px] flex-shrink-0",
                  isActive && "text-primary",
                  isAdminItem && !isActive && "text-destructive"
                )} />
              )}
              <span className="truncate">{item.label}</span>
            </button>
          );
        })}
      </nav>

      {/* Logout */}
      <div className="p-3 border-t border-border/30">
        <button
          className="w-full flex items-center gap-3 h-11 px-4 rounded-xl text-sm font-medium text-destructive hover:bg-destructive/10 transition-colors duration-200 active:scale-[0.98]"
          onClick={async () => {
            await signOut();
            navigate('/login');
            onItemClick?.();
          }}
        >
          <LogOut className="h-[18px] w-[18px] flex-shrink-0" />
          Déconnexion
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Skeleton } from "@/components/ui/skeleton";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/integrations/supabase/client";
import { useAIItemAssistant } from "@/hooks/useAIItemAssistant";
import { Habit } from "@/types";
import { Sparkles, Loader2 } from "lucide-react";

interface CreateHabitFormProps {
  onSuccess: () => void;
  habit?: Habit | null;
}

interface Goal {
  id: string;
  title: string;
}

export default function CreateHabitForm({ onSuccess, habit }: CreateHabitFormProps) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    frequency: 'daily',
    category: '',
    target: 1,
    linked_goal_id: 'none',
    days_of_week: [] as number[]
  });
  const [loading, setLoading] = useState(false);
  const [goals, setGoals] = useState<Goal[]>([]);

  const { user } = useAuth();
  const { toast } = useToast();
  const { suggest, isLoading: isAILoading } = useAIItemAssistant();

  useEffect(() => {
    if (habit) {
      setFormData({
        title: habit.title,
        description: habit.description || '',
        frequency: habit.frequency,
        category: habit.category || '',
        target: habit.target,
        linked_goal_id: 'none',
        days_of_week: habit.days_of_week || []
      });
      fetchHabitGoalLink(habit.id);
    } else {
      setFormData({
        title: '',
        description: '',
        frequency: 'daily',
        category: '',
        target: 1,
        linked_goal_id: 'none',
        days_of_week: []
      });
    }
    fetchGoals();
  }, [habit]);

  const fetchHabitGoalLink = async (habitId: string) => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('habits')
        .select('linked_goal_id')
        .eq('id', habitId)
        .eq('user_id', user.id)
        .single();
      if (error) throw error;
      setFormData(prev => ({ ...prev, linked_goal_id: data?.linked_goal_id || 'none' }));
    } catch (error) {
      console.error('Error fetching habit goal link:', error);
    }
  };

  const fetchGoals = async () => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('goals')
        .select('id, title')
        .eq('user_id', user.id)
        .eq('completed', false)
        .order('created_at', { ascending: false });
      if (error) throw error;
      setGoals(data || []);
    } catch (error) {
      console.error('Error fetching goals:', error);
    }
  };

  const handleAISuggest = async () => {
    if (!formData.title.trim()) {
      toast({ title: "Erreur", description: "Entrez d'abord un titre.", variant: "destructive" });
      return;
    }
    const result = await suggest({ type: "habit", title: formData.title });
    if (result && 'frequency' in result) {
      setFormData(prev => ({
        ...prev,
        description: result.description || prev.description,
        frequency: result.frequency || prev.frequency,
        category: result.category || prev.category,
      }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !formData.title.trim()) {
      toast({ title: "Erreur", description: "Le titre est obligatoire.", variant: "destructive" });
      return;
    }

    setLoading(true);
    try {
      const habitData = {
        title: formData.title.trim(),
        description: formData.description.trim() || null,
        frequency: formData.frequency,
        category: formData.category.trim() || null,
        target: formData.target,
        user_id: user.id,
        linked_goal_id: formData.linked_goal_id === 'none' ? null : formData.linked_goal_id,
        days_of_week: formData.days_of_week.length > 0 ? formData.days_of_week : null
      };

      if (habit) {
        const { error } = await supabase
          .from('habits')
          .update({ ...habitData, updated_at: new Date().toISOString() })
          .eq('id', habit.id)
          .eq('user_id', user.id);
        if (error) throw error;
        toast({ title: "Habitude modifiée", description: "Votre habitude a été mise à jour avec succès." });
      } else {
        const { error } = await supabase.from('habits').insert(habitData);
        if (error) throw error;
        toast({ title: "Habitude créée", description: "Votre nouvelle habitude a été créée avec succès." });
      }
      onSuccess();
    } catch (error) {
      console.error('Error saving habit:', error);
      toast({ title: "Erreur", description: "Impossible de sauvegarder l'habitude.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <Label htmlFor="title">Titre *</Label>
        <Input
          id="title"
          value={formData.title}
          onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
          placeholder="Ex: Faire du sport"
          required
        />
      </div>

      <div>
        <div className="flex items-center justify-between mb-1">
          <Label htmlFor="description">Description</Label>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={handleAISuggest}
            disabled={isAILoading || !formData.title.trim()}
            className="h-7 gap-1.5 text-xs text-primary hover:text-primary/80"
          >
            {isAILoading ? (
              <Loader2 className="h-3.5 w-3.5 animate-spin" />
            ) : (
              <Sparkles className="h-3.5 w-3.5" />
            )}
            {isAILoading ? "Génération..." : "✨ Remplir avec l'IA"}
          </Button>
        </div>
        {isAILoading ? (
          <div className="space-y-2">
            <Skeleton className="h-20 w-full rounded-xl" />
            <Skeleton className="h-4 w-2/3 rounded-lg" />
          </div>
        ) : (
          <Textarea
            id="description"
            value={formData.description}
            onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
            placeholder="Description optionnelle de l'habitude"
            rows={3}
          />
        )}
      </div>

      <div>
        <Label htmlFor="frequency">Fréquence *</Label>
        {isAILoading ? (
          <Skeleton className="h-10 w-full rounded-xl" />
        ) : (
          <Select
            value={formData.frequency}
            onValueChange={(value) => setFormData(prev => ({ ...prev, frequency: value }))}
          >
            <SelectTrigger>
              <SelectValue placeholder="Choisir la fréquence" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="daily">Quotidienne</SelectItem>
              <SelectItem value="weekly">Hebdomadaire</SelectItem>
              <SelectItem value="monthly">Mensuelle</SelectItem>
            </SelectContent>
          </Select>
        )}
      </div>

      <div>
        <Label htmlFor="category">Catégorie</Label>
        {isAILoading ? (
          <Skeleton className="h-10 w-full rounded-xl" />
        ) : (
          <Input
            id="category"
            value={formData.category}
            onChange={(e) => setFormData(prev => ({ ...prev, category: e.target.value }))}
            placeholder="Ex: Santé, Travail, Personnel"
          />
        )}
      </div>

      <div>
        <Label htmlFor="target">Objectif numérique</Label>
        <Input
          id="target"
          type="number"
          min="1"
          value={formData.target}
          onChange={(e) => setFormData(prev => ({ ...prev, target: parseInt(e.target.value) || 1 }))}
          placeholder="1"
        />
      </div>

      <div>
        <Label>Jours de la semaine (optionnel)</Label>
        <p className="text-xs text-muted-foreground mb-2">
          Laissez vide pour tous les jours, ou sélectionnez des jours spécifiques
        </p>
        <div className="grid grid-cols-7 gap-2 mt-2">
          {[
            { label: 'Dim', value: 0 },
            { label: 'Lun', value: 1 },
            { label: 'Mar', value: 2 },
            { label: 'Mer', value: 3 },
            { label: 'Jeu', value: 4 },
            { label: 'Ven', value: 5 },
            { label: 'Sam', value: 6 }
          ].map((day) => (
            <div key={day.value} className="flex flex-col items-center space-y-1">
              <span className="text-xs text-muted-foreground">{day.label}</span>
              <Checkbox
                checked={formData.days_of_week.includes(day.value)}
                onCheckedChange={(checked) => {
                  if (checked) {
                    setFormData(prev => ({
                      ...prev,
                      days_of_week: [...prev.days_of_week, day.value].sort()
                    }));
                  } else {
                    setFormData(prev => ({
                      ...prev,
                      days_of_week: prev.days_of_week.filter(d => d !== day.value)
                    }));
                  }
                }}
              />
            </div>
          ))}
        </div>
      </div>

      <div>
        <Label htmlFor="linked_goal">Lier à un objectif</Label>
        <Select
          value={formData.linked_goal_id}
          onValueChange={(value) => setFormData(prev => ({ ...prev, linked_goal_id: value }))}
        >
          <SelectTrigger>
            <SelectValue placeholder="Choisir un objectif (optionnel)" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="none">Aucun objectif</SelectItem>
            {goals.map((goal) => (
              <SelectItem key={goal.id} value={goal.id}>
                {goal.title}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <Button type="submit" className="w-full" disabled={loading}>
        {loading ? "Sauvegarde..." : (habit ? "Modifier" : "Créer")}
      </Button>
    </form>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/integrations/supabase/client";
import { useAIItemAssistant } from "@/hooks/useAIItemAssistant";
import { Task } from "@/types";
import { Sparkles, Loader2 } from "lucide-react";

interface CreateTaskFormProps {
  onSuccess: () => void;
  task?: Task | null;
}

interface Goal {
  id: string;
  title: string;
}

export default function CreateTaskForm({ onSuccess, task }: CreateTaskFormProps) {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<"high" | "medium" | "low">("medium");
  const [dueDate, setDueDate] = useState("");
  const [linkedGoalId, setLinkedGoalId] = useState("none");
  const [goals, setGoals] = useState<Goal[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { user } = useAuth();
  const { suggest, isLoading: isAILoading } = useAIItemAssistant();

  useEffect(() => {
    if (task) {
      setTitle(task.title);
      setDescription(task.description || "");
      setPriority(task.priority);
      setDueDate(task.due_date ? new Date(task.due_date).toISOString().split('T')[0] : "");
      fetchTaskGoalLink(task.id);
    }
    fetchGoals();
  }, [task]);

  const fetchTaskGoalLink = async (taskId: string) => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('linked_goal_id')
        .eq('id', taskId)
        .eq('user_id', user.id)
        .single();
      if (error) throw error;
      setLinkedGoalId(data?.linked_goal_id || "none");
    } catch (error) {
      console.error('Error fetching task goal link:', error);
      setLinkedGoalId("none");
    }
  };

  const fetchGoals = async () => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('goals')
        .select('id, title')
        .eq('user_id', user.id)
        .eq('completed', false)
        .order('created_at', { ascending: false });
      if (error) throw error;
      setGoals(data || []);
    } catch (error) {
      console.error('Error fetching goals:', error);
    }
  };

  const handleAISuggest = async () => {
    if (!title.trim()) {
      toast.error("Entrez d'abord un titre.");
      return;
    }
    const result = await suggest({ type: "task", title });
    if (result && 'priority' in result) {
      if (result.description) setDescription(result.description);
      if (result.priority) setPriority(result.priority);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !title.trim()) return;

    setIsSubmitting(true);
    try {
      const taskData = {
        title: title.trim(),
        description: description.trim() || null,
        priority,
        due_date: dueDate || null,
        user_id: user.id,
        linked_goal_id: linkedGoalId === "none" ? null : linkedGoalId,
      };

      let error;
      if (task) {
        ({ error } = await supabase
          .from('tasks')
          .update(taskData)
          .eq('id', task.id)
          .eq('user_id', user.id));
      } else {
        ({ error } = await supabase
          .from('tasks')
          .insert(taskData));
      }

      if (error) throw error;

      toast.success(task ? 'Tâche modifiée !' : 'Tâche créée !');
      onSuccess();
    } catch (error) {
      console.error("Error saving task:", error);
      toast.error("Erreur lors de la sauvegarde de la tâche");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="space-y-2">
        <Label htmlFor="title">Titre *</Label>
        <Input
          id="title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="Nom de votre tâche"
          required
        />
      </div>

      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <Label htmlFor="description">Description</Label>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={handleAISuggest}
            disabled={isAILoading || !title.trim()}
            className="h-7 gap-1.5 text-xs text-primary hover:text-primary/80"
          >
            {isAILoading ? (
              <Loader2 className="h-3.5 w-3.5 animate-spin" />
            ) : (
              <Sparkles className="h-3.5 w-3.5" />
            )}
            {isAILoading ? "Génération..." : "✨ Remplir avec l'IA"}
          </Button>
        </div>
        {isAILoading ? (
          <div className="space-y-2">
            <Skeleton className="h-20 w-full rounded-xl" />
          </div>
        ) : (
          <Textarea
            id="description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Description de votre tâche (optionnel)"
          />
        )}
      </div>

      <div className="space-y-2">
        <Label htmlFor="priority">Priorité *</Label>
        {isAILoading ? (
          <Skeleton className="h-10 w-full rounded-xl" />
        ) : (
          <Select value={priority} onValueChange={(value: "high" | "medium" | "low") => setPriority(value)} required>
            <SelectTrigger>
              <SelectValue placeholder="Sélectionner une priorité" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="high">Haute</SelectItem>
              <SelectItem value="medium">Moyenne</SelectItem>
              <SelectItem value="low">Basse</SelectItem>
            </SelectContent>
          </Select>
        )}
      </div>

      <div className="space-y-2">
        <Label htmlFor="dueDate">Date d'échéance</Label>
        <Input
          id="dueDate"
          type="date"
          value={dueDate}
          onChange={(e) => setDueDate(e.target.value)}
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="linked_goal">Lier à un objectif</Label>
        <Select value={linkedGoalId} onValueChange={setLinkedGoalId}>
          <SelectTrigger>
            <SelectValue placeholder="Choisir un objectif (optionnel)" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="none">Aucun objectif</SelectItem>
            {goals.map((goal) => (
              <SelectItem key={goal.id} value={goal.id}>
                {goal.title}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <Button type="submit" disabled={isSubmitting || !title.trim()} className="w-full">
        {isSubmitting ? "Sauvegarde..." : task ? "Modifier la tâche" : "Créer la tâche"}
      </Button>
    </form>
  );
}

import React, { useState, createContext, useContext, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { FoodType } from "@/hooks/usePenguinRewards";

interface Notification {
  id: string;
  type: 'food' | 'evolution';
  foodType?: FoodType;
  message: string;
}

interface FoodNotificationContextType {
  showFood: (foodType: FoodType, message: string) => void;
  showEvolution: (stageName: string) => void;
}

const FoodNotificationContext = createContext<FoodNotificationContextType | null>(null);

export const useFoodNotification = () => {
  const context = useContext(FoodNotificationContext);
  if (!context) {
    return {
      showFood: () => {},
      showEvolution: () => {},
    };
  }
  return context;
};

const FOOD_COLORS: Record<string, string> = {
  shrimp: 'from-orange-400/20 to-orange-500/10 border-orange-400/30',
  salmon: 'from-rose-400/20 to-rose-500/10 border-rose-400/30',
  golden_fish: 'from-amber-400/20 to-amber-500/10 border-amber-400/30',
};

const FOOD_EMOJIS: Record<string, string> = {
  shrimp: '🦐',
  salmon: '🐟',
  golden_fish: '✨🐠',
};

export const FoodNotificationProvider = ({ children }: { children: React.ReactNode }) => {
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((n: Notification) => {
    setNotifications(prev => [...prev, n]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(x => x.id !== n.id));
    }, 3000);
  }, []);

  const showFood = useCallback((foodType: FoodType, message: string) => {
    addNotification({ id: crypto.randomUUID(), type: 'food', foodType, message });
  }, [addNotification]);

  const showEvolution = useCallback((stageName: string) => {
    addNotification({ id: crypto.randomUUID(), type: 'evolution', message: `🐧 Évolution : ${stageName} !` });
  }, [addNotification]);

  return (
    <FoodNotificationContext.Provider value={{ showFood, showEvolution }}>
      {children}
      <div className="fixed top-4 right-4 z-[100] space-y-2 pointer-events-none">
        <AnimatePresence>
          {notifications.map((n) => (
            <motion.div
              key={n.id}
              initial={{ opacity: 0, x: 80, scale: 0.8 }}
              animate={{ opacity: 1, x: 0, scale: 1 }}
              exit={{ opacity: 0, x: 80, scale: 0.8 }}
              className={`px-4 py-3 rounded-2xl border backdrop-blur-md bg-gradient-to-r shadow-lg ${
                n.type === 'evolution'
                  ? 'from-sky-400/20 to-indigo-500/10 border-sky-400/30'
                  : FOOD_COLORS[n.foodType || 'shrimp']
              }`}
            >
              <div className="flex items-center gap-2">
                {n.type === 'food' && (
                  <span className="text-xl">{FOOD_EMOJIS[n.foodType || 'shrimp']}</span>
                )}
                {n.type === 'evolution' && (
                  <span className="text-xl">🐧</span>
                )}
                <span className="text-sm font-medium text-foreground">{n.message}</span>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </FoodNotificationContext.Provider>
  );
};

