import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface TaskSuggestion {
  description: string;
  priority: "high" | "medium" | "low";
  due_date_suggestion?: string;
  subtasks: string[];
}

interface HabitSuggestion {
  description: string;
  frequency: string;
  category: string;
  tips: string;
}

interface GoalSuggestion {
  description: string;
  category: string;
  milestones: string[];
}

export type AISuggestion = TaskSuggestion | HabitSuggestion | GoalSuggestion;

interface SuggestParams {
  type: "task" | "habit" | "goal";
  title: string;
  existingData?: Record<string, unknown>;
}

export function useAIItemAssistant() {
  const [isLoading, setIsLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<AISuggestion | null>(null);

  const suggest = async ({ type, title, existingData }: SuggestParams): Promise<AISuggestion | null> => {
    if (!title.trim()) {
      toast.error("Entrez d'abord un titre pour obtenir des suggestions IA.");
      return null;
    }

    setIsLoading(true);
    setSuggestion(null);

    try {
      const { data, error } = await supabase.functions.invoke("ai-item-assistant", {
        body: { type, title: title.trim(), existingData },
      });

      if (error) throw error;

      if (data?.error === "AI_LIMIT_REACHED") {
        toast.error(data.message || "Limite IA quotidienne atteinte.");
        return null;
      }

      if (data?.suggestion) {
        setSuggestion(data.suggestion);
        toast.success("✨ Suggestions IA générées !");
        return data.suggestion;
      } else {
        toast.error("L'IA n'a pas pu générer de suggestions.");
        return null;
      }
    } catch (error: any) {
      console.error("AI suggestion error:", error);
      if (error?.message?.includes("429")) {
        toast.error("Trop de requêtes, réessayez dans un moment.");
      } else {
        toast.error("Erreur lors de la génération IA.");
      }
      return null;
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => setSuggestion(null);

  return { suggest, isLoading, suggestion, reset };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";

export interface AdminAnnouncement {
  id: string;
  title: string;
  content: string;
  is_active: boolean;
  announcement_type: 'info' | 'warning' | 'success' | 'update';
  created_at: string;
  updated_at: string;
  created_by?: string;
}

export const useAdminAnnouncements = () => {
  const { user, isAdmin } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Fetch active announcements for all users using raw query
  const { data: announcements, isLoading } = useQuery({
    queryKey: ["admin-announcements"],
    queryFn: async () => {
      // Use rpc or direct fetch since table might not be in types yet
      const { data, error } = await supabase
        .from("admin_announcements" as any)
        .select("*")
        .eq("is_active", true)
        .order("created_at", { ascending: false });

      if (error) {
        console.error("Error fetching announcements:", error);
        return [];
      }
      return (data || []) as unknown as AdminAnnouncement[];
    },
  });

  // Create announcement (admin only)
  const createAnnouncement = useMutation({
    mutationFn: async (announcement: Omit<AdminAnnouncement, 'id' | 'created_at' | 'updated_at'>) => {
      if (!user || !isAdmin) throw new Error("Not authorized");

      const { data, error } = await supabase
        .from("admin_announcements" as any)
        .insert({
          ...announcement,
          created_by: user.id,
        })
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-announcements"] });
      toast({
        title: "Annonce créée",
        description: "L'annonce a été publiée avec succès",
      });
    },
    onError: (error) => {
      toast({
        title: "Erreur",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  // Update announcement (admin only)
  const updateAnnouncement = useMutation({
    mutationFn: async ({ id, ...updates }: Partial<AdminAnnouncement> & { id: string }) => {
      if (!isAdmin) throw new Error("Not authorized");

      const { data, error } = await supabase
        .from("admin_announcements" as any)
        .update(updates)
        .eq("id", id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-announcements"] });
      toast({
        title: "Annonce mise à jour",
        description: "L'annonce a été modifiée avec succès",
      });
    },
  });

  // Delete announcement (admin only)
  const deleteAnnouncement = useMutation({
    mutationFn: async (id: string) => {
      if (!isAdmin) throw new Error("Not authorized");

      const { error } = await supabase
        .from("admin_announcements" as any)
        .delete()
        .eq("id", id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-announcements"] });
      toast({
        title: "Annonce supprimée",
        description: "L'annonce a été supprimée",
      });
    },
  });

  return {
    announcements: announcements || [],
    isLoading,
    createAnnouncement: createAnnouncement.mutate,
    updateAnnouncement: updateAnnouncement.mutate,
    deleteAnnouncement: deleteAnnouncement.mutate,
    isAdmin,
  };
};

import { useState, useEffect, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { format, subDays, startOfToday, parseISO } from "date-fns";

type AnalyticsDataType = {
  // Types de données pour les graphiques
  habitsData: { name: string; value: number }[];
  tasksData: { name: string; completed: number; pending: number }[];
  focusData: { date: string; minutes: number }[];
  activityData: { date: string; count: number }[];
  taskCompletionRate: number;
  totalFocusTime: number;
  streakCount: number;
  isLoading: boolean;
  error: string | null;
  refetch: () => Promise<void>;
};

export const useAnalyticsData = (): AnalyticsDataType => {
  const [habitsData, setHabitsData] = useState<{ name: string; value: number }[]>([]);
  const [tasksData, setTasksData] = useState<{ name: string; completed: number; pending: number }[]>([]);
  const [focusData, setFocusData] = useState<{ date: string; minutes: number }[]>([]);
  const [activityData, setActivityData] = useState<{ date: string; count: number }[]>([]);
  const [taskCompletionRate, setTaskCompletionRate] = useState<number>(0);
  const [totalFocusTime, setTotalFocusTime] = useState<number>(0);
  const [streakCount, setStreakCount] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { user } = useAuth();

  const fetchData = useCallback(async () => {
    if (!user) return;

    setIsLoading(true);
    setError(null);

    try {
      // Récupérer les données des habitudes
      const { data: habitsRawData, error: habitsError } = await supabase
        .from('habits')
        .select('title, id, streak')
        .eq('user_id', user.id);

      if (habitsError) throw new Error("Erreur lors de la récupération des habitudes: " + habitsError.message);

      // Format the habit data using the correct column name (title instead of name)
      let maxStreak = 0;
      const formattedHabitsData = (habitsRawData || []).map(habit => {
        const streak = habit.streak || 0;
        if (streak > maxStreak) maxStreak = streak;
        return {
          name: habit.title, // Using 'title' instead of 'name'
          value: streak
        };
      });

      // Update global streak count
      setStreakCount(maxStreak);

      // Set habits data
      setHabitsData(formattedHabitsData.length > 0 ? formattedHabitsData : [
        { name: "Pas d'habitudes", value: 0 }
      ]);

      // Récupérer les données des tâches
      const { data: tasksRawData, error: tasksError } = await supabase
        .from('tasks')
        .select('priority, completed')
        .eq('user_id', user.id);

      if (tasksError) throw new Error("Erreur lors de la récupération des tâches: " + tasksError.message);

      // Calculate task completion rate
      const totalTasks = (tasksRawData || []).length;
      const completedTasks = (tasksRawData || []).filter(task => task.completed).length;
      setTaskCompletionRate(totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0);

      // Regrouper par priorité
      const tasksByPriority = (tasksRawData || []).reduce((acc: Record<string, {completed: number, pending: number}>, task) => {
        const priority = task.priority || 'non-défini';
        if (!acc[priority]) {
          acc[priority] = { completed: 0, pending: 0 };
        }

        if (task.completed) {
          acc[priority].completed += 1;
        } else {
          acc[priority].pending += 1;
        }

        return acc;
      }, {});

      const formattedTasksData = Object.entries(tasksByPriority).map(([name, data]) => ({
        name: name === 'high' ? 'Élevée' : name === 'medium' ? 'Moyenne' : name === 'low' ? 'Faible' : 'Non-définie',
        completed: data.completed,
        pending: data.pending
      }));

      setTasksData(formattedTasksData.length > 0 ? formattedTasksData : [
        { name: "Pas de tâches", completed: 0, pending: 0 }
      ]);

      // Récupérer les données des sessions focus
      const { data: focusRawData, error: focusError } = await supabase
        .from('focus_sessions')
        .select('duration, created_at')
        .eq('user_id', user.id)
        .gt('created_at', subDays(new Date(), 14).toISOString())
        .order('created_at', { ascending: false });

      if (focusError) throw new Error("Erreur lors de la récupération des sessions focus: " + focusError.message);

      // Calculer le temps total de focus en minutes
      let totalMinutes = 0;

      // Formater les données de focus
      const focusByDay: Record<string, number> = {};
      const last7Days = Array.from({ length: 7 }).map((_, i) => {
        const date = new Date();
        date.setDate(date.getDate() - i);
        const formattedDate = format(date, 'yyyy-MM-dd');
        focusByDay[formattedDate] = 0;
        return formattedDate;
      }).reverse();

      // Agréger les sessions par jour
      (focusRawData || []).forEach(session => {
        const sessionDate = format(parseISO(session.created_at), 'yyyy-MM-dd');
        const durationMinutes = Math.round(session.duration / 60);
        totalMinutes += durationMinutes;

        if (last7Days.includes(sessionDate)) {
          focusByDay[sessionDate] = (focusByDay[sessionDate] || 0) + durationMinutes;
        }
      });

      // Mettre à jour le temps total de focus
      setTotalFocusTime(totalMinutes);

      // Formater les données pour le graphique
      const formattedFocusData = Object.entries(focusByDay).map(([date, minutes]) => ({
        date: format(parseISO(date), 'dd MMM'),
        minutes
      }));

      setFocusData(formattedFocusData);

      // Récupérer les données d'activité générale
      const last7DaysDates = [...Array(7)].map((_, i) => {
        const date = new Date();
        date.setDate(date.getDate() - i);
        return date.toISOString().split('T')[0];
      }).reverse();

      // Compter toutes les activités par jour en utilisant des requêtes directes
      const startDate = last7DaysDates[0];
      const endDate = last7DaysDates[last7DaysDates.length - 1] + 'T23:59:59';

      // Get habits activity
      const { data: habitsActivityData, error: habitsActivityError } = await supabase
        .from('habits')
        .select('updated_at')
        .eq('user_id', user.id)
        .gte('updated_at', startDate)
        .lte('updated_at', endDate);

      // Get tasks activity
      const { data: tasksActivityData, error: tasksActivityError } = await supabase
        .from('tasks')
        .select('updated_at')
        .eq('user_id', user.id)
        .gte('updated_at', startDate)
        .lte('updated_at', endDate);

      // Get focus sessions activity
      const { data: focusActivityData, error: focusActivityError } = await supabase
        .from('focus_sessions')
        .select('created_at')
        .eq('user_id', user.id)
        .gte('created_at', startDate)
        .lte('created_at', endDate);

      // Get journal entries activity
      const { data: journalActivityData, error: journalActivityError } = await supabase
        .from('journal_entries')
        .select('created_at')
        .eq('user_id', user.id)
        .gte('created_at', startDate)
        .lte('created_at', endDate);

      if (habitsActivityError || tasksActivityError || focusActivityError || journalActivityError) {
        throw new Error("Erreur lors de la récupération des données d'activité: " 
          + (habitsActivityError || tasksActivityError || focusActivityError || journalActivityError).message);
      }

      // Combine all activity data
      const allActivityData = [
        ...(habitsActivityData || []).map(item => ({ date: new Date(item.updated_at).toISOString().split('T')[0] })),
        ...(tasksActivityData || []).map(item => ({ date: new Date(item.updated_at).toISOString().split('T')[0] })),
        ...(focusActivityData || []).map(item => ({ date: new Date(item.created_at).toISOString().split('T')[0] })),
        ...(journalActivityData || []).map(item => ({ date: new Date(item.created_at).toISOString().split('T')[0] }))
      ];

      // Mapper les activités par jour
      const activityByDay: Record<string, number> = {};
      last7DaysDates.forEach(day => {
        activityByDay[day] = 0;
      });

      allActivityData.forEach(item => {
        if (activityByDay[item.date] !== undefined) {
          activityByDay[item.date] += 1;
        }
      });

      const formattedActivityData = Object.entries(activityByDay).map(([date, count]) => ({
        date: format(parseISO(date), 'dd MMM'),
        count
      }));

      setActivityData(formattedActivityData);

    } catch (err: any) {
      console.error("Erreur lors de la récupération des données pour l'analyse:", err);
      setError(err.message || "Erreur lors du chargement des données d'analyse");

      // Définir des données par défaut en cas d'erreur
      if (habitsData.length === 0) {
        setHabitsData([{ name: "Pas de données", value: 0 }]);
      }
      if (tasksData.length === 0) {
        setTasksData([{ name: "Pas de données", completed: 0, pending: 0 }]);
      }
      if (focusData.length === 0) {
        setFocusData([{ date: "Aujourd'hui", minutes: 0 }]);
      }
      if (activityData.length === 0) {
        setActivityData([{ date: "Aujourd'hui", count: 0 }]);
      }
    } finally {
      setIsLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      fetchData();
    }
  }, [user, fetchData]);

  return {
    habitsData,
    tasksData,
    focusData,
    activityData,
    taskCompletionRate,
    totalFocusTime,
    streakCount,
    isLoading,
    error,
    refetch: fetchData
  };
};

import { createContext, useContext, useEffect, useState, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Session, User } from "@supabase/supabase-js";

interface AuthContextType {
  session: Session | null;
  user: User | null;
  isAdmin: boolean;
  isLoading: boolean;
  signIn: (email: string, password: string) => Promise<{
    error: any;
    data: any;
  }>;
  signUp: (email: string, password: string) => Promise<{
    error: any;
    data: any;
  }>;
  signOut: () => Promise<{ error: any }>;
  resetPassword: (email: string) => Promise<{
    error: any;
    data: any;
  }>;
}

const AuthContext = createContext<AuthContextType>({
  session: null,
  user: null,
  isAdmin: false,
  isLoading: true,
  signIn: async () => ({ error: null, data: null }),
  signUp: async () => ({ error: null, data: null }),
  signOut: async () => ({ error: null }),
  resetPassword: async () => ({ error: null, data: null }),
});

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [session, setSession] = useState<Session | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Function to check admin role - memoized to prevent recreating
  const checkAdminRole = useCallback(async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('user_roles')
        .select('role')
        .eq('user_id', userId)
        .eq('role', 'admin')
        .maybeSingle();

      if (error) {
        console.error("Error checking admin role:", error);
        setIsAdmin(false);
        return;
      }

      setIsAdmin(!!data);
    } catch (error) {
      console.error("Error checking admin role:", error);
      setIsAdmin(false);
    }
  }, []);

  useEffect(() => {
    let mounted = true;

    // Set up auth state listener FIRST (before checking existing session)
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, newSession) => {
      if (!mounted) return;

      console.log("Auth state changed:", event, newSession?.user?.email);

      // Only update session state synchronously - no async calls in callback
      setSession(newSession);
      setUser(newSession?.user ?? null);

      if (event === 'SIGNED_OUT') {
        setIsAdmin(false);
        setIsLoading(false);
      } else if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED' || event === 'INITIAL_SESSION') {
        if (newSession?.user) {
          // Immediately perform admin check, then stop loading
          checkAdminRole(newSession.user.id).finally(() => {
            if (mounted) setIsLoading(false);
          });
        } else {
          setIsLoading(false);
        }
      }
    });

    // THEN check for existing session
    const initSession = async () => {
      try {
        const { data: { session: existingSession }, error } = await supabase.auth.getSession();

        if (error) {
          console.error("Error getting session:", error);
          if (mounted) setIsLoading(false);
          return;
        }

        console.log("Initial session check:", existingSession ? `Found session for ${existingSession.user?.email}` : "No session");

        if (mounted) {
          setSession(existingSession);
          setUser(existingSession?.user ?? null);

          if (existingSession?.user) {
            await checkAdminRole(existingSession.user.id);
          }
        }
      } catch (error) {
        console.error("Error checking auth:", error);
      } finally {
        if (mounted) setIsLoading(false);
      }
    };

    initSession();

    // Cleanup subscription on unmount
    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, [checkAdminRole]);

  const signIn = async (email: string, password: string) => {
    console.log("Signing in with email:", email);
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password
    });

    return { data, error };
  };

  const signUp = async (email: string, password: string) => {
    console.log("Signing up with email:", email);
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: window.location.origin
      }
    });

    return { data, error };
  };

  const signOut = async () => {
    console.log("Signing out (local scope only)");
    // Use 'local' scope to only sign out on this device, not all devices
    const { error } = await supabase.auth.signOut({ scope: 'local' });
    return { error };
  };

  const resetPassword = async (email: string) => {
    console.log("Resetting password for:", email);
    const { data, error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/reset-password`,
    });

    return { data, error };
  };

  return (
    <AuthContext.Provider
      value={{
        session,
        user,
        isAdmin,
        isLoading,
        signIn,
        signUp,
        signOut,
        resetPassword,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "./useAuth";
import { Task, Habit, Goal } from "@/types";

export interface CalendarItem {
  id: string;
  title: string;
  description?: string;
  date: string;
  type: 'task' | 'habit' | 'goal' | 'google_event';
  completed?: boolean;
  priority?: string;
  category?: string;
  source?: 'local' | 'google';
}

export function useCalendarData(selectedDate: Date) {
  const { user } = useAuth();
  const [items, setItems] = useState<CalendarItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (user && selectedDate) {
      loadCalendarData();
    }
  }, [user, selectedDate]);

  const loadCalendarData = async () => {
    if (!user) return;

    setIsLoading(true);
    try {
      // Calculate week range
      const startOfWeek = new Date(selectedDate);
      startOfWeek.setDate(selectedDate.getDate() - selectedDate.getDay() + 1); // Monday
      startOfWeek.setHours(0, 0, 0, 0);

      const endOfWeek = new Date(startOfWeek);
      endOfWeek.setDate(startOfWeek.getDate() + 6); // Sunday
      endOfWeek.setHours(23, 59, 59, 999);

      // Charger les tâches pour toute la semaine
      const { data: tasks } = await supabase
        .from('tasks')
        .select('*')
        .eq('user_id', user.id)
        .gte('due_date', startOfWeek.toISOString())
        .lte('due_date', endOfWeek.toISOString());

      // Charger les objectifs pour toute la semaine
      const { data: goals } = await supabase
        .from('goals')
        .select('*')
        .eq('user_id', user.id)
        .gte('target_date', startOfWeek.toISOString())
        .lte('target_date', endOfWeek.toISOString());

      // Charger les événements Google Calendar
      const googleEvents = await loadGoogleEvents(startOfWeek, endOfWeek);

      const calendarItems: CalendarItem[] = [];

      // Ajouter les tâches
      tasks?.forEach((task: any) => {
        calendarItems.push({
          id: task.id,
          title: task.title,
          description: task.description || undefined,
          date: task.due_date,
          type: 'task',
          completed: task.completed,
          priority: task.priority || undefined,
          source: 'local'
        });
      });

      // Ajouter les objectifs
      goals?.forEach((goal: any) => {
        calendarItems.push({
          id: goal.id,
          title: goal.title,
          description: goal.description || undefined,
          date: goal.target_date,
          type: 'goal',
          completed: goal.completed,
          category: goal.category,
          source: 'local'
        });
      });

      // Ajouter les événements Google
      calendarItems.push(...googleEvents);

      setItems(calendarItems);
    } catch (error) {
      console.error('Error loading calendar data:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const loadGoogleEvents = async (startDate: Date, endDate: Date): Promise<CalendarItem[]> => {
    if (!user) return [];

    try {
      // Vérifier si Google Calendar est connecté
      const { data: tokenData } = await supabase
        .from("google_calendar_tokens")
        .select("*")
        .eq("user_id", user.id)
        .single();

      if (!tokenData) return [];

      const { data: eventsData, error } = await supabase.functions.invoke("google-calendar-api", {
        body: {
          action: "list",
          user_id: user.id,
          time_min: startDate.toISOString(),
          time_max: endDate.toISOString(),
        },
      });

      if (error) {
        console.error("Error fetching Google events:", error);
        return [];
      }

      return (eventsData?.items || []).map((event: any) => ({
        id: event.id,
        title: event.summary || 'Sans titre',
        date: event.start?.dateTime || event.start?.date,
        type: 'google_event' as const,
        completed: false,
        description: event.description,
        source: 'google' as const
      }));
    } catch (error) {
      console.error("Error loading Google events:", error);
      return [];
    }
  };

  return { items, isLoading, reload: loadCalendarData };
}

import { useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "./useAuth";

export const useEnsurePenguinProfile = () => {
  const { user } = useAuth();

  useEffect(() => {
    const ensure = async () => {
      if (!user) return;

      const { data: profile } = await supabase
        .from("penguin_profiles")
        .select("id")
        .eq("user_id", user.id)
        .maybeSingle();

      if (!profile) {
        await supabase
          .from("penguin_profiles")
          .insert({ user_id: user.id })
          .select()
          .single();
      }

      // Also ensure AI credits
      const { data: credits } = await supabase
        .from("ai_credits")
        .select("id")
        .eq("user_id", user.id)
        .maybeSingle();

      if (!credits) {
        await supabase
          .from("ai_credits")
          .insert({ user_id: user.id, credits: 50 })
          .select()
          .single();
      }
    };

    ensure();
  }, [user?.id]);
};

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "./useAuth";
import { toast } from "sonner";

interface CalendarEvent {
  id: string;
  summary: string;
  description?: string;
  start: { dateTime?: string; date?: string };
  end: { dateTime?: string; date?: string };
}

export function useGoogleCalendar() {
  const { user } = useAuth();
  const [isConnected, setIsConnected] = useState(false);
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (user) {
      checkConnection();
    }
  }, [user]);

  const checkConnection = async () => {
    if (!user) return;

    const { data } = await supabase
      .from("google_calendar_tokens")
      .select("*")
      .eq("user_id", user.id)
      .single();

    setIsConnected(!!data);
  };

  const loadEvents = async (startDate: Date, endDate: Date) => {
    if (!user) return;

    setIsLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke("google-calendar-api", {
        body: {
          action: "list",
          user_id: user.id,
          time_min: startDate.toISOString(),
          time_max: endDate.toISOString(),
        },
      });

      if (error) throw error;
      setEvents(data.items || []);
    } catch (error) {
      console.error("Error loading events:", error);
      toast.error("Erreur de chargement des événements");
    } finally {
      setIsLoading(false);
    }
  };

  const createEvent = async (eventData: {
    title: string;
    description?: string;
    startDateTime: string;
    endDateTime: string;
  }) => {
    if (!user) return;

    setIsLoading(true);
    try {
      const { error } = await supabase.functions.invoke("google-calendar-api", {
        body: {
          action: "create",
          user_id: user.id,
          event_data: {
            summary: eventData.title,
            description: eventData.description,
            start: { dateTime: eventData.startDateTime, timeZone: "Europe/Paris" },
            end: { dateTime: eventData.endDateTime, timeZone: "Europe/Paris" },
          },
        },
      });

      if (error) throw error;
      toast.success("Événement créé !");
      return true;
    } catch (error) {
      console.error("Error creating event:", error);
      toast.error("Erreur de création de l'événement");
      return false;
    } finally {
      setIsLoading(false);
    }
  };

  const deleteEvent = async (eventId: string) => {
    if (!user) return;

    setIsLoading(true);
    try {
      const { error } = await supabase.functions.invoke("google-calendar-api", {
        body: {
          action: "delete",
          user_id: user.id,
          event_id: eventId,
        },
      });

      if (error) throw error;
      toast.success("Événement supprimé !");
      return true;
    } catch (error) {
      console.error("Error deleting event:", error);
      toast.error("Erreur de suppression de l'événement");
      return false;
    } finally {
      setIsLoading(false);
    }
  };

  return {
    isConnected,
    events,
    isLoading,
    loadEvents,
    createEvent,
    deleteEvent,
    checkConnection,
  };
}

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "./useAuth";
import { toast } from "sonner";

interface GoogleTask {
  id: string;
  title: string;
  notes?: string;
  due?: string;
  status: string;
  completed?: string;
}

export function useGoogleTasks() {
  const { user } = useAuth();
  const [isConnected, setIsConnected] = useState(false);
  const [tasks, setTasks] = useState<GoogleTask[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [taskListId, setTaskListId] = useState<string>("");

  useEffect(() => {
    if (user) {
      checkConnection();
    }
  }, [user]);

  const checkConnection = async () => {
    if (!user) return;

    const { data } = await supabase
      .from("google_tasks_tokens")
      .select("*")
      .eq("user_id", user.id)
      .single();

    setIsConnected(!!data);
  };

  const connectToGoogle = async () => {
    if (!user) return;

    try {
      const { data, error } = await supabase.functions.invoke("google-tasks-oauth", {
        body: { action: "get_auth_url" },
      });

      if (error) throw error;

      window.location.href = data.authUrl;
    } catch (error) {
      console.error("Error connecting to Google Tasks:", error);
      toast.error("Erreur de connexion à Google Tasks");
    }
  };

  const handleOAuthCallback = async (code: string) => {
    if (!user) return;

    try {
      const { error } = await supabase.functions.invoke("google-tasks-oauth", {
        body: { code },
      });

      if (error) throw error;

      toast.success("Connecté à Google Tasks !");
      setIsConnected(true);
    } catch (error) {
      console.error("Error in OAuth callback:", error);
      toast.error("Erreur lors de la connexion");
    }
  };

  const disconnect = async () => {
    if (!user) return;

    try {
      const { error } = await supabase
        .from("google_tasks_tokens")
        .delete()
        .eq("user_id", user.id);

      if (error) throw error;

      setIsConnected(false);
      setTasks([]);
      toast.success("Déconnecté de Google Tasks");
    } catch (error) {
      console.error("Error disconnecting:", error);
      toast.error("Erreur lors de la déconnexion");
    }
  };

  const loadTasks = async (listId?: string) => {
    if (!user) return;

    setIsLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke("google-tasks-api", {
        body: {
          action: "list",
          user_id: user.id,
          task_list_id: listId || taskListId,
        },
      });

      if (error) throw error;
      setTasks(data.items || []);

      if (!taskListId && data.items?.[0]) {
        // Get the task list ID from the first request
        const { data: listsData } = await supabase.functions.invoke("google-tasks-api", {
          body: {
            action: "list_task_lists",
            user_id: user.id,
          },
        });
        setTaskListId(listsData?.items?.[0]?.id || "");
      }
    } catch (error) {
      console.error("Error loading tasks:", error);
      toast.error("Erreur de chargement des tâches");
    } finally {
      setIsLoading(false);
    }
  };

  const createTask = async (taskData: { title: string; notes?: string; due?: string }) => {
    if (!user) return null;

    setIsLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke("google-tasks-api", {
        body: {
          action: "create",
          user_id: user.id,
          task_list_id: taskListId,
          task_data: taskData,
        },
      });

      if (error) throw error;
      toast.success("Tâche créée dans Google Tasks !");
      await loadTasks();
      return data?.id || null;
    } catch (error) {
      console.error("Error creating task:", error);
      toast.error("Erreur de création de la tâche");
      return null;
    } finally {
      setIsLoading(false);
    }
  };

  const updateTask = async (taskId: string, taskData: Partial<GoogleTask>) => {
    if (!user) return false;

    setIsLoading(true);
    try {
      const { error } = await supabase.functions.invoke("google-tasks-api", {
        body: {
          action: "update",
          user_id: user.id,
          task_list_id: taskListId,
          task_id: taskId,
          task_data: taskData,
        },
      });

      if (error) throw error;
      toast.success("Tâche mise à jour !");
      await loadTasks();
      return true;
    } catch (error) {
      console.error("Error updating task:", error);
      toast.error("Erreur de mise à jour");
      return false;
    } finally {
      setIsLoading(false);
    }
  };

  const deleteTask = async (taskId: string) => {
    if (!user) return false;

    setIsLoading(true);
    try {
      const { error } = await supabase.functions.invoke("google-tasks-api", {
        body: {
          action: "delete",
          user_id: user.id,
          task_list_id: taskListId,
          task_id: taskId,
        },
      });

      if (error) throw error;
      toast.success("Tâche supprimée !");
      await loadTasks();
      return true;
    } catch (error) {
      console.error("Error deleting task:", error);
      toast.error("Erreur de suppression");
      return false;
    } finally {
      setIsLoading(false);
    }
  };

  return {
    isConnected,
    tasks,
    isLoading,
    connectToGoogle,
    handleOAuthCallback,
    disconnect,
    loadTasks,
    createTask,
    updateTask,
    deleteTask,
    checkConnection,
  };
}

import { useState, useEffect } from 'react';
import { useAuth } from './useAuth';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

export interface PersonalityProfile {
  personality: {
    traits: string[];
    strengths: string[];
    areas_to_improve: string[];
    motivations: string[];
    working_style: string;
  };
  psychological_insights: {
    behavioral_patterns: string[];
    stress_management: string;
    decision_making_style: string;
    social_preferences: string;
  };
  productivity_analysis: {
    peak_performance_times: string[];
    productivity_blockers: string[];
    optimal_work_environment: string;
    goal_achievement_style: string;
  };
  recommendations: {
    habits_to_develop: string[];
    productivity_tips: string[];
    personal_growth: string[];
    stress_management: string[];
  };
  growth_trajectory: {
    current_phase: string;
    next_milestones: string[];
    long_term_potential: string;
  };
}

export const usePersonalityProfile = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState<PersonalityProfile | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isInitialLoading, setIsInitialLoading] = useState(true);

  // Load saved profile on mount
  useEffect(() => {
    if (!user) {
      setIsInitialLoading(false);
      return;
    }

    const loadSavedProfile = async () => {
      try {
        setIsInitialLoading(true);
        const { data, error } = await supabase
          .from('ai_personality_profiles')
          .select('profile_data')
          .eq('user_id', user.id)
          .maybeSingle();

        if (data?.profile_data) {
          setProfile(data.profile_data as unknown as PersonalityProfile);
        }
      } catch (error) {
        console.error("Error loading saved profile:", error);
      } finally {
        setIsInitialLoading(false);
      }
    };

    loadSavedProfile();
  }, [user]);

  const generateProfile = async () => {
    if (!user) {
      console.log('Pas d\'utilisateur connecté');
      return;
    }

    console.log('Début de la génération du profil pour l\'utilisateur:', user.id);
    setIsLoading(true);
    try {
      // Récupérer TOUTES les données utilisateur sans limites strictes
      const [habitsResult, goalsResult, tasksResult, journalResult, focusResult, habitCompletionsResult, reflectionsResult] = await Promise.allSettled([
        supabase.from('habits').select('*').eq('user_id', user.id),
        supabase.from('goals').select('*').eq('user_id', user.id),
        supabase.from('tasks').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(100),
        supabase.from('journal_entries').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(50),
        supabase.from('focus_sessions').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(50),
        supabase.from('habit_completions').select('*').eq('user_id', user.id).order('completed_date', { ascending: false }).limit(100),
        supabase.from('daily_reflections').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(30)
      ]);

      // Extraire les données de manière sécurisée
      const habits = habitsResult.status === 'fulfilled' ? habitsResult.value.data || [] : [];
      const goals = goalsResult.status === 'fulfilled' ? goalsResult.value.data || [] : [];
      const tasks = tasksResult.status === 'fulfilled' ? tasksResult.value.data || [] : [];
      const journal = journalResult.status === 'fulfilled' ? journalResult.value.data || [] : [];
      const focus = focusResult.status === 'fulfilled' ? focusResult.value.data || [] : [];
      const habitCompletions = habitCompletionsResult.status === 'fulfilled' ? habitCompletionsResult.value.data || [] : [];
      const reflections = reflectionsResult.status === 'fulfilled' ? reflectionsResult.value.data || [] : [];

      console.log('Données récupérées:', { habits: habits.length, goals: goals.length, tasks: tasks.length, journal: journal.length, focus: focus.length });

      // Calculer des métriques avancées
      const now = new Date();
      const last30Days = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const last7Days = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

      // Analyse temporelle des habitudes
      const recentHabitCompletions = habitCompletions.filter(hc => new Date(hc.completed_date) > last30Days);
      const habitConsistencyRate = habits.length > 0 ? (recentHabitCompletions.length / (habits.length * 30)) * 100 : 0;

      // Analyse des tâches
      const completedTasks = tasks.filter(t => t.completed);
      const taskCompletionRate = tasks.length > 0 ? (completedTasks.length / tasks.length) * 100 : 0;
      const recentTasks = tasks.filter(t => new Date(t.created_at) > last7Days);
      const highPriorityTasks = tasks.filter(t => t.priority === 'high');
      const highPriorityCompleted = highPriorityTasks.filter(t => t.completed);

      // Analyse des objectifs
      const activeGoals = goals.filter(g => !g.completed && !g.is_archived);
      const completedGoals = goals.filter(g => g.completed);
      const avgGoalProgress = activeGoals.length > 0 ? activeGoals.reduce((acc, g) => acc + (g.progress || 0), 0) / activeGoals.length : 0;

      // Analyse du focus
      const recentFocus = focus.filter(f => new Date(f.created_at) > last30Days);
      const totalFocusTime = recentFocus.reduce((acc, f) => acc + (f.duration || 0), 0);
      const avgFocusSession = recentFocus.length > 0 ? totalFocusTime / recentFocus.length : 0;
      const focusFrequency = recentFocus.length / 30;

      // Analyse du journal
      const recentJournals = journal.filter(j => new Date(j.created_at) > last30Days);
      const moodDistribution = recentJournals.reduce((acc, j) => {
        const mood = j.mood || 'unknown';
        acc[mood] = (acc[mood] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);
      const dominantMood = Object.entries(moodDistribution).sort((a, b) => b[1] - a[1])[0]?.[0] || 'neutral';

      // Patterns temporels
      const tasksByDayOfWeek = tasks.reduce((acc, t) => {
        const day = new Date(t.created_at).getDay();
        acc[day] = (acc[day] || 0) + 1;
        return acc;
      }, {} as Record<number, number>);
      const mostProductiveDay = Object.entries(tasksByDayOfWeek).sort((a, b) => b[1] - a[1])[0]?.[0];

      const focusByHour = focus.reduce((acc, f) => {
        const hour = new Date(f.created_at).getHours();
        acc[hour] = (acc[hour] || 0) + 1;
        return acc;
      }, {} as Record<number, number>);
      const peakFocusHour = Object.entries(focusByHour).sort((a, b) => b[1] - a[1])[0]?.[0];

      // Créer un résumé détaillé pour une analyse psychologique approfondie
      const userSummary = {
        vue_generale: {
          total_habitudes: habits.length,
          total_objectifs: goals.length,
          total_taches: tasks.length,
          total_sessions_focus: focus.length,
          total_entrees_journal: journal.length,
          total_reflexions: reflections.length
        },
        metriques_performance: {
          taux_completion_taches: Math.round(taskCompletionRate),
          taux_completion_objectifs: goals.length > 0 ? Math.round((completedGoals.length / goals.length) * 100) : 0,
          consistance_habitudes: Math.round(habitConsistencyRate),
          progression_objectifs_moyenne: Math.round(avgGoalProgress),
          temps_focus_total_30j: Math.round(totalFocusTime),
          duree_moyenne_focus: Math.round(avgFocusSession),
          frequence_focus_quotidienne: focusFrequency.toFixed(1)
        },
        analyse_habitudes: {
          habitudes_actives: habits.filter(h => !h.is_archived).length,
          meilleur_streak: Math.max(...habits.map(h => h.streak || 0), 0),
          streak_moyen: Math.round(habits.reduce((acc, h) => acc + (h.streak || 0), 0) / Math.max(habits.length, 1)),
          categories: [...new Set(habits.map(h => h.category).filter(Boolean))],
          frequences: habits.map(h => ({ titre: h.title, freq: h.frequency, streak: h.streak })),
          completions_30_derniers_jours: recentHabitCompletions.length
        },
        analyse_objectifs: {
          objectifs_actifs: activeGoals.length,
          objectifs_completes: completedGoals.length,
          objectifs_archives: goals.filter(g => g.is_archived).length,
          categories: [...new Set(goals.map(g => g.category).filter(Boolean))],
          details: goals.map(g => ({
            titre: g.title,
            progression: g.progress,
            complete: g.completed,
            categorie: g.category,
            description: g.description?.substring(0, 100)
          }))
        },
        analyse_taches: {
          taches_completees: completedTasks.length,
          taches_en_cours: tasks.length - completedTasks.length,
          taches_haute_priorite: highPriorityTasks.length,
          taux_completion_haute_priorite: highPriorityTasks.length > 0 ? Math.round((highPriorityCompleted.length / highPriorityTasks.length) * 100) : 0,
          taches_recentes_7j: recentTasks.length,
          repartition_priorites: {
            high: tasks.filter(t => t.priority === 'high').length,
            medium: tasks.filter(t => t.priority === 'medium').length,
            low: tasks.filter(t => t.priority === 'low').length
          },
          objectifs_lies: tasks.filter(t => t.linked_goal_id).length
        },
        analyse_focus: {
          sessions_30j: recentFocus.length,
          temps_total_minutes: Math.round(totalFocusTime),
          temps_moyen_session: Math.round(avgFocusSession),
          sessions_par_jour: focusFrequency.toFixed(1),
          heure_pic_concentration: peakFocusHour || 'non défini',
          sessions_recentes: recentFocus.slice(0, 10).map(f => ({
            duree: f.duration,
            date: f.created_at,
            titre: f.title
          }))
        },
        analyse_emotionnelle: {
          entrees_journal_30j: recentJournals.length,
          humeur_dominante: dominantMood,
          distribution_humeurs: moodDistribution,
          frequence_journaling: (recentJournals.length / 30).toFixed(1),
          reflexions_recentes: reflections.length,
          themes_journal: recentJournals.flatMap(j => j.tags || []).filter(Boolean)
        },
        patterns_comportementaux: {
          jour_plus_productif: mostProductiveDay ? ['Dimanche', 'Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi'][parseInt(mostProductiveDay)] : 'non défini',
          heure_pic_focus: peakFocusHour || 'non défini',
          regularite_hebdomadaire: Object.values(tasksByDayOfWeek).length,
          style_travail: avgFocusSession > 45 ? 'sessions longues' : avgFocusSession > 25 ? 'sessions moyennes' : 'sessions courtes'
        },
        contexte_psychologique: {
          niveau_engagement: habitConsistencyRate > 70 ? 'élevé' : habitConsistencyRate > 40 ? 'moyen' : 'faible',
          orientation_objectifs: activeGoals.length > completedGoals.length ? 'ambitieux' : 'pragmatique',
          gestion_priorites: highPriorityTasks.length > tasks.length * 0.3 ? 'orienté urgence' : 'équilibré',
          pratique_reflexive: recentJournals.length > 15 ? 'très régulière' : recentJournals.length > 5 ? 'régulière' : 'occasionnelle'
        }
      };

      console.log('Résumé utilisateur créé avec métriques avancées');

      // Tenter d'abord l'API Gemini avec analyse approfondie
      try {
        console.log('Invocation de l\'IA pour analyse psychologique approfondie...');
        const { data, error } = await supabase.functions.invoke('gemini-chat-enhanced', {
          body: {
            message: `ANALYSE PSYCHOLOGIQUE APPROFONDIE - Profil de Personnalité

Tu dois analyser en profondeur toutes ces données et créer un profil psychologique vraiment personnalisé et utile.

DONNÉES COMPLÈTES DE L'UTILISATEUR:
${JSON.stringify(userSummary, null, 2)}

INSTRUCTIONS CRITIQUES:
1. Analyse RÉELLEMENT toutes les métriques et patterns fournis
2. Identifie des traits psychologiques spécifiques basés sur les comportements observés
3. Fais des connexions entre les différentes données (ex: lien entre humeur et productivité)
4. Sois PRÉCIS et PERSONNALISÉ - évite les généralités
5. Utilise les chiffres et patterns réels pour justifier tes insights
6. Identifie des blocages psychologiques potentiels basés sur les patterns
7. Propose des recommandations vraiment adaptées au profil comportemental observé

FORMAT DE RÉPONSE (JSON strict, sans texte avant/après):
{
  "personality": {
    "traits": ["3-5 traits psychologiques SPÉCIFIQUES déduits des patterns comportementaux"],
    "strengths": ["3-5 forces RÉELLES identifiées dans les données"],
    "areas_to_improve": ["2-4 zones d'amélioration CONCRÈTES basées sur les métriques"],
    "motivations": ["2-4 motivations DÉDUITES du type d'objectifs et habitudes"],
    "working_style": "Description DÉTAILLÉE du style de travail basée sur les patterns de focus et tâches"
  },
  "psychological_insights": {
    "behavioral_patterns": ["3-5 patterns comportementaux OBSERVÉS dans les données"],
    "stress_management": "Analyse du stress basée sur humeurs, focus et régularité",
    "decision_making_style": "Style de décision déduit des priorités et choix d'objectifs",
    "social_preferences": "Préférences déduites du type d'objectifs et réflexions"
  },
  "productivity_analysis": {
    "peak_performance_times": ["Moments identifiés dans les données de focus et tâches"],
    "productivity_blockers": ["Blocages RÉELS identifiés dans les patterns"],
    "optimal_work_environment": "Environnement optimal basé sur les sessions de focus réussies",
    "goal_achievement_style": "Style basé sur la progression réelle des objectifs"
  },
  "recommendations": {
    "habits_to_develop": ["3-5 habitudes SPÉCIFIQUES pour combler les gaps identifiés"],
    "productivity_tips": ["3-5 tips PERSONNALISÉS basés sur le profil"],
    "personal_growth": ["3-5 conseils de croissance ADAPTÉS aux zones d'amélioration"],
    "stress_management": ["3-5 techniques APPROPRIÉES au profil de stress observé"]
  },
  "growth_trajectory": {
    "current_phase": "Phase actuelle déduite des métriques de progression",
    "next_milestones": ["3-4 jalons LOGIQUES basés sur les objectifs et progression actuels"],
    "long_term_potential": "Potentiel basé sur les tendances et la consistance observées"
  }
}

Réponds UNIQUEMENT avec le JSON valide, aucun texte supplémentaire.`,
            context: {
              analysis_mode: true,
              user_data: userSummary
            }
          }
        });

        if (!error && data?.response) {
          const responseText = data.response;
          console.log('Réponse IA reçue:', responseText);

          if (typeof responseText === 'string') {
            const cleanedResponse = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
            const analysisResult = JSON.parse(cleanedResponse);

            if (analysisResult.personality) {
              setProfile(analysisResult);

              console.log('Sauvegarde du profil dans Supabase...');
              // Save to database
              const { error: saveError } = await supabase
                .from('ai_personality_profiles')
                .upsert({
                  user_id: user.id,
                  profile_data: analysisResult as Record<string, unknown>,
                  updated_at: new Date().toISOString()
                }, {
                  onConflict: 'user_id'
                });

              if (saveError) {
                console.error('Erreur lors de la sauvegarde du profil:', saveError);
                throw saveError;
              }

              toast.success('Profil de personnalité généré et sauvegardé !');
              return;
            }
          }
        }
      } catch (aiError) {
        console.log('API IA non disponible, utilisation de l\'analyse locale:', aiError);
      }

      // Fallback : génération basée sur les vraies données utilisateur
      console.log('Génération du profil basé sur les données réelles...');

      const analysisResult: PersonalityProfile = {
        personality: {
          traits: generatePersonalityTraits(userSummary),
          strengths: generateStrengths(userSummary),
          areas_to_improve: generateImprovementAreas(userSummary),
          motivations: generateMotivations(userSummary),
          working_style: generateWorkingStyle(userSummary)
        },
        psychological_insights: {
          behavioral_patterns: generateBehavioralPatterns(userSummary),
          stress_management: generateStressManagement(userSummary),
          decision_making_style: generateDecisionStyle(userSummary),
          social_preferences: generateSocialPreferences(userSummary)
        },
        productivity_analysis: {
          peak_performance_times: generatePeakTimes(userSummary),
          productivity_blockers: generateBlockers(userSummary),
          optimal_work_environment: generateOptimalEnvironment(userSummary),
          goal_achievement_style: generateGoalStyle(userSummary)
        },
        recommendations: {
          habits_to_develop: generateHabitRecommendations(userSummary),
          productivity_tips: generateProductivityTips(userSummary),
          personal_growth: generateGrowthRecommendations(userSummary),
          stress_management: generateStressRecommendations(userSummary)
        },
        growth_trajectory: {
          current_phase: generateCurrentPhase(userSummary),
          next_milestones: generateMilestones(userSummary),
          long_term_potential: generateLongTermPotential(userSummary)
        }
      };

      setProfile(analysisResult);

      console.log('Sauvegarde du profil (fallback) dans Supabase...');
      // Save to database
      const { error: saveError } = await supabase
        .from('ai_personality_profiles')
        .upsert({
          user_id: user.id,
          profile_data: analysisResult as Record<string, unknown>,
          updated_at: new Date().toISOString()
        }, {
          onConflict: 'user_id'
        });

      if (saveError) {
        console.error('Erreur lors de la sauvegarde du profil (fallback):', saveError);
        throw saveError;
      }

      toast.success('Profil de personnalité généré et sauvegardé !');

    } catch (error: unknown) {
      const err = error as Record<string, any>;
      console.error('Erreur génération profil:', err);

      // Gestion des erreurs spécifiques
      if (err?.message?.includes('429') || err?.message?.includes('quota') || err?.message?.includes('Too Many Requests')) {
        toast.error('Limite d\'API atteinte. Réessayez dans quelques minutes.');
      } else if (error?.message?.includes('Réponse IA invalide')) {
        toast.error('Erreur dans l\'analyse IA. Réessayez.');
      } else {
        toast.error('Erreur lors de la génération du profil');
      }
    } finally {
      setIsLoading(false);
    }
  };

  return {
    profile,
    isLoading,
    isInitialLoading,
    generateProfile
  };
};

// Fonctions d'analyse basées sur les données réelles
const generatePersonalityTraits = (data: Record<string, any>) => {
  const traits = [];
  const taskCompletionRate = data.metriques_performance?.taux_completion_taches || 0;
  if (taskCompletionRate > 70) traits.push("déterminé");
  if (data.vue_generale?.total_habitudes > 3) traits.push("discipliné");
  if (data.analyse_focus?.sessions_30j > 5) traits.push("concentré");
  if (data.analyse_objectifs?.objectifs_completes > 0) traits.push("ambitieux");
  return traits.length > 0 ? traits : ["motivé", "organisé"];
};

const generateStrengths = (data: Record<string, any>) => {
  const strengths = [];
  if (data.analyse_habitudes?.streak_moyen > 5) strengths.push("constance dans les habitudes");
  const taskCompletionRate = data.metriques_performance?.taux_completion_taches || 0;
  if (taskCompletionRate > 60) strengths.push("efficacité dans l'exécution");
  if (data.analyse_focus?.temps_total_minutes > 120) strengths.push("capacité de concentration");
  return strengths.length > 0 ? strengths : ["motivation", "persévérance"];
};

const generateImprovementAreas = (data: Record<string, any>) => {
  const areas = [];
  if (data.analyse_focus?.temps_total_minutes < 60) areas.push("temps de concentration");
  const taskCompletionRate = data.metriques_performance?.taux_completion_taches || 0;
  if (taskCompletionRate < 50) areas.push("gestion des tâches");
  if (data.analyse_habitudes?.completions_30_derniers_jours < 3) areas.push("régularité des habitudes");
  return areas.length > 0 ? areas : ["équilibre vie-travail", "gestion du stress"];
};

const generateMotivations = (data: Record<string, any>) => {
  const motivations = [];
  if (data.vue_generale?.total_objectifs > 2) motivations.push("accomplissement d'objectifs");
  if (data.vue_generale?.total_habitudes > 2) motivations.push("amélioration continue");
  motivations.push("développement personnel");
  return motivations;
};

const generateWorkingStyle = (data: Record<string, any>) => {
  if (data.analyse_focus?.sessions_30j > 5) return "focalisé sur la concentration";
  if (data.vue_generale?.total_taches > 10) return "orienté tâches";
  return "équilibré et adaptable";
};

const generateBehavioralPatterns = (data: Record<string, any>) => {
  const patterns = [];
  if (data.analyse_habitudes?.habitudes_actives > 0) patterns.push("formation d'habitudes");
  if (data.analyse_focus?.sessions_30j > 0) patterns.push("sessions de travail focalisé");
  patterns.push("planification d'objectifs");
  return patterns;
};

const generateStressManagement = (data: Record<string, any>) => {
  if (data.analyse_focus?.temps_moyen_session > 30) return "gestion par la concentration";
  if (data.analyse_habitudes?.habitudes_actives > 3) return "gestion par les routines";
  return "approche équilibrée";
};

const generateDecisionStyle = (data: Record<string, any>) => {
  if (data.metriques_performance?.progression_objectifs_moyenne > 50) return "orienté résultats";
  if (data.analyse_taches?.taches_haute_priorite > 0) return "priorise l'urgence";
  return "réfléchi et méthodique";
};

const generateSocialPreferences = (data: Record<string, any>) => {
  if (data.analyse_focus?.sessions_30j > 3) return "préfère le travail concentré";
  return "équilibre social et travail";
};

const generatePeakTimes = (data: Record<string, any>) => {
  const times = [];
  if (data.analyse_focus?.sessions_30j > 0) times.push("périodes de focus planifiées");
  times.push("matinée");
  return times;
};

const generateBlockers = (data: Record<string, any>) => {
  const blockers = [];
  const taskCompletionRate = data.metriques_performance?.taux_completion_taches || 0;
  if (taskCompletionRate < 50) blockers.push("procrastination");
  if (data.analyse_focus?.temps_total_minutes < 60) blockers.push("difficultés de concentration");
  return blockers.length > 0 ? blockers : ["distractions", "surcharge de tâches"];
};

const generateOptimalEnvironment = (data: Record<string, any>) => {
  if (data.analyse_focus?.sessions_30j > 3) return "environnement calme et organisé";
  return "espace flexible et adaptatif";
};

const generateGoalStyle = (data: Record<string, any>) => {
  if (data.metriques_performance?.progression_objectifs_moyenne > 60) return "approche progressive et mesurée";
  if (data.vue_generale?.total_objectifs > 2) return "objectifs multiples et ambitieux";
  return "approche étape par étape";
};

const generateHabitRecommendations = (data: Record<string, any>) => {
  const recommendations = [];
  if (data.analyse_focus?.temps_total_minutes < 60) recommendations.push("sessions de concentration quotidiennes");
  if (data.vue_generale?.total_habitudes < 3) recommendations.push("routine matinale structurée");
  recommendations.push("pause active régulière");
  return recommendations;
};

const generateProductivityTips = (data: Record<string, any>) => {
  const tips = [];
  const taskCompletionRate = data.metriques_performance?.taux_completion_taches || 0;
  if (taskCompletionRate < 60) tips.push("technique Pomodoro");
  if (data.metriques_performance?.progression_objectifs_moyenne < 50) tips.push("décomposition d'objectifs");
  tips.push("planification hebdomadaire");
  return tips;
};

const generateGrowthRecommendations = (data: Record<string, any>) => {
  const growth = [];
  if (data.vue_generale?.total_entrees_journal < 3) growth.push("tenue de journal régulière");
  growth.push("auto-évaluation mensuelle");
  growth.push("lecture de développement personnel");
  return growth;
};

const generateStressRecommendations = (data: Record<string, any>) => {
  const stress = [];
  if (data.metriques_performance?.duree_moyenne_focus < 25) stress.push("techniques de respiration");
  stress.push("pauses régulières");
  stress.push("activité physique");
  return stress;
};

const generateCurrentPhase = (data: Record<string, any>) => {
  if (data.vue_generale?.total_habitudes > 3 && data.metriques_performance?.progression_objectifs_moyenne > 50) return "phase d'optimisation";
  if (data.vue_generale?.total_taches > 5) return "phase de développement actif";
  return "phase d'établissement des bases";
};

const generateMilestones = (data: Record<string, any>) => {
  const milestones = [];
  if (data.analyse_habitudes?.streak_moyen < 7) milestones.push("maintenir 7 jours d'habitudes");
  const taskCompletionRate = data.metriques_performance?.taux_completion_taches || 0;
  if (taskCompletionRate < 80) milestones.push("atteindre 80% de tâches complétées");
  milestones.push("développer une routine optimale");
  return milestones;
};

const generateLongTermPotential = (data: Record<string, any>) => {
  if (data.vue_generale?.total_objectifs > 2 && data.vue_generale?.total_habitudes > 3) return "expert en productivité personnelle";
  if (data.analyse_focus?.sessions_30j > 3) return "maître de la concentration";
  return "développeur de systèmes personnels efficaces";
};

import { useMemo } from 'react';
import { useAnalyticsData } from './useAnalyticsData';
import { 
  TrendingUp, TrendingDown, Clock, Target, 
  Calendar, Zap, AlertTriangle, CheckCircle,
  Brain, Heart, Trophy, Flame
} from 'lucide-react';

export interface ProductivityInsight {
  id: string;
  title: string;
  insight: string;
  recommendation: string;
  description?: string;
  suggestion?: string;
  priority: 'high' | 'medium' | 'low';
  icon: any;
  metric?: string;
  category: 'performance' | 'habits' | 'focus' | 'motivation' | 'optimization';
}

export const useProductivityInsights = (): ProductivityInsight[] => {
  const { 
    taskCompletionRate, 
    totalFocusTime, 
    streakCount, 
    habitsData, 
    focusData,
    activityData 
  } = useAnalyticsData();

  return useMemo(() => {
    const insights: ProductivityInsight[] = [];

    // Calculs préliminaires
    const dailyFocusAverage = totalFocusTime / 7;
    const avgStreakDays = habitsData.length > 0 
      ? habitsData.reduce((sum, habit) => sum + habit.value, 0) / habitsData.length
      : 0;
    const recentActivity = activityData.slice(-7).reduce((sum, day) => sum + day.count, 0);
    const focusConsistency = focusData.filter(day => day.minutes > 0).length;

    // Insights de performance
    if (taskCompletionRate < 40) {
      insights.push({
        id: 'critical-completion',
        title: 'Performance critique',
        insight: `Votre taux de complétion de ${taskCompletionRate.toFixed(0)}% nécessite une action immédiate.`,
        recommendation: 'Utilisez la technique des 3 tâches prioritaires par jour. Commencez petit et célébrez chaque victoire.',
        description: `Votre taux de complétion de ${taskCompletionRate.toFixed(0)}% nécessite une action immédiate.`,
        suggestion: 'Utilisez la technique des 3 tâches prioritaires par jour. Commencez petit et célébrez chaque victoire.',
        priority: 'high',
        icon: AlertTriangle,
        metric: `${taskCompletionRate.toFixed(0)}%`,
        category: 'performance'
      });
    } else if (taskCompletionRate >= 90) {
      insights.push({
        id: 'exceptional-performance',
        title: 'Performance exceptionnelle',
        insight: `Votre taux de ${taskCompletionRate.toFixed(0)}% vous place dans l'élite des utilisateurs productifs.`,
        recommendation: 'Partagez vos méthodes avec d\'autres et challengez-vous avec des projets plus ambitieux.',
        description: `Votre taux de ${taskCompletionRate.toFixed(0)}% vous place dans l'élite des utilisateurs productifs.`,
        suggestion: 'Partagez vos méthodes avec d\'autres et challengez-vous avec des projets plus ambitieux.',
        priority: 'low',
        icon: Trophy,
        metric: `${taskCompletionRate.toFixed(0)}%`,
        category: 'performance'
      });
    } else if (taskCompletionRate < 60) {
      insights.push({
        id: 'improving-completion',
        title: 'Potentiel d\'amélioration',
        insight: `À ${taskCompletionRate.toFixed(0)}%, vous avez une belle marge de progression.`,
        recommendation: 'Analysez vos tâches non terminées et identifiez les obstacles récurrents.',
        description: `À ${taskCompletionRate.toFixed(0)}%, vous avez une belle marge de progression.`,
        suggestion: 'Analysez vos tâches non terminées et identifiez les obstacles récurrents.',
        priority: 'medium',
        icon: TrendingUp,
        metric: `${taskCompletionRate.toFixed(0)}%`,
        category: 'performance'
      });
    }

    // Insights de focus
    if (dailyFocusAverage < 20) {
      insights.push({
        id: 'focus-deficit',
        title: 'Déficit de concentration',
        insight: `${dailyFocusAverage.toFixed(0)} minutes par jour est insuffisant pour une productivité optimale.`,
        recommendation: 'Commencez par des sessions de 15 minutes. Éliminez les distractions de votre environnement.',
        priority: 'high',
        icon: Brain,
        metric: `${dailyFocusAverage.toFixed(0)}min/jour`,
        category: 'focus'
      });
    } else if (dailyFocusAverage >= 180) {
      insights.push({
        id: 'focus-master',
        title: 'Maître de la concentration',
        insight: `${dailyFocusAverage.toFixed(0)} minutes quotidiennes révèlent une discipline remarquable.`,
        recommendation: 'Variez vos techniques de focus et veillez à maintenir un équilibre vie-travail.',
        priority: 'low',
        icon: Zap,
        metric: `${dailyFocusAverage.toFixed(0)}min/jour`,
        category: 'focus'
      });
    }

    // Insights de consistance
    if (focusConsistency <= 2) {
      insights.push({
        id: 'inconsistent-focus',
        title: 'Focus irrégulier',
        insight: `Seulement ${focusConsistency} jours avec des sessions de focus cette semaine.`,
        recommendation: 'Intégrez 20 minutes de focus dans votre routine matinale quotidienne.',
        priority: 'medium',
        icon: Calendar,
        metric: `${focusConsistency}/7 jours`,
        category: 'habits'
      });
    } else if (focusConsistency === 7) {
      insights.push({
        id: 'perfect-consistency',
        title: 'Consistance parfaite',
        insight: 'Vous avez maintenu des sessions de focus tous les jours cette semaine !',
        recommendation: 'Récompensez-vous et maintenez cette excellente habitude.',
        priority: 'low',
        icon: Flame,
        metric: '7/7 jours',
        category: 'habits'
      });
    }

    // Insights d'habitudes
    if (avgStreakDays < 2 && habitsData.length > 0) {
      insights.push({
        id: 'habit-struggle',
        title: 'Difficultés avec les habitudes',
        insight: `Vos séries moyennes de ${avgStreakDays.toFixed(1)} jours indiquent des difficultés de constance.`,
        recommendation: 'Réduisez à 1-2 habitudes essentielles et utilisez des rappels visuels.',
        priority: 'high',
        icon: TrendingDown,
        metric: `${avgStreakDays.toFixed(1)} jours`,
        category: 'habits'
      });
    } else if (avgStreakDays >= 14) {
      insights.push({
        id: 'habit-champion',
        title: 'Champion des habitudes',
        insight: `${avgStreakDays.toFixed(1)} jours de série moyenne témoignent d'une discipline extraordinaire.`,
        recommendation: 'Documentez votre méthode et envisagez de mentorer d\'autres personnes.',
        priority: 'low',
        icon: Heart,
        metric: `${avgStreakDays.toFixed(1)} jours`,
        category: 'habits'
      });
    }

    // Insights d'activité générale
    if (recentActivity < 10) {
      insights.push({
        id: 'low-engagement',
        title: 'Engagement faible',
        insight: `${recentActivity} activités cette semaine suggèrent un manque d'engagement.`,
        recommendation: 'Planifiez 3 activités minimum par jour et utilisez des récompenses pour vous motiver.',
        priority: 'medium',
        icon: AlertTriangle,
        metric: `${recentActivity} activités`,
        category: 'motivation'
      });
    } else if (recentActivity >= 30) {
      insights.push({
        id: 'high-activity',
        title: 'Très actif',
        insight: `${recentActivity} activités montrent un excellent niveau d'engagement.`,
        recommendation: 'Assurez-vous de prendre des pauses pour éviter le burnout.',
        priority: 'low',
        icon: CheckCircle,
        metric: `${recentActivity} activités`,
        category: 'motivation'
      });
    }

    // Insights d'optimisation
    const weekendActivity = activityData.slice(-2).reduce((sum, day) => sum + day.count, 0);
    const weekdayActivity = activityData.slice(-7, -2).reduce((sum, day) => sum + day.count, 0);

    if (weekendActivity > weekdayActivity * 0.6) {
      insights.push({
        id: 'weekend-productivity',
        title: 'Productivité weekend',
        insight: 'Vous êtes plus productif le weekend que les jours de semaine.',
        recommendation: 'Analysez ce qui rend vos weekends productifs et appliquez ces principes en semaine.',
        priority: 'medium',
        icon: Target,
        category: 'optimization'
      });
    }

    // Trier par priorité et limiter le nombre
    const priorityOrder = { high: 3, medium: 2, low: 1 };
    return insights
      .sort((a, b) => priorityOrder[b.priority] - priorityOrder[a.priority])
      .slice(0, 8); // Limiter à 8 insights max
  }, [taskCompletionRate, totalFocusTime, streakCount, habitsData, focusData, activityData]);
};

import { useState, useEffect } from 'react';
import { useAnalyticsData } from './useAnalyticsData';
import { useAuth } from './useAuth';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

export interface ProductivityMetrics {
  score: number;
  level: string;
  badges: string[];
  streakBonus: number;
  completionRate: number;
  focusTimeScore: number;
  consistencyScore: number;
  qualityScore: number;
  timeManagementScore: number;
  journalScore: number;
  goalScore: number;
}

export const useProductivityScoreAI = (): ProductivityMetrics => {
  const { user } = useAuth();
  const { 
    taskCompletionRate, 
    totalFocusTime, 
    streakCount, 
    habitsData, 
    focusData,
    activityData 
  } = useAnalyticsData();

  const [aiMetrics, setAiMetrics] = useState<ProductivityMetrics>({
    score: 0,
    level: 'Débutant',
    badges: [],
    streakBonus: 0,
    completionRate: 0,
    focusTimeScore: 0,
    consistencyScore: 0,
    qualityScore: 0,
    timeManagementScore: 0,
    journalScore: 0,
    goalScore: 0
  });

  const [isCalculating, setIsCalculating] = useState(false);

  useEffect(() => {
    if (user && !isCalculating) {
      calculateProductivityWithAI();
    }
  }, [user, taskCompletionRate, totalFocusTime, streakCount, habitsData.length, focusData.length, activityData.length]);

  const calculateProductivityWithAI = async () => {
    if (!user || isCalculating) return;

    setIsCalculating(true);

    try {
      console.log("Calculating productivity score with AI...");

      // Récupérer toutes les données utilisateur pour l'analyse
      const [
        tasksResult,
        habitsResult,
        goalsResult,
        journalResult,
        focusResult
      ] = await Promise.allSettled([
        supabase.from('tasks').select('*').eq('user_id', user.id),
        supabase.from('habits').select('*').eq('user_id', user.id),
        supabase.from('goals').select('*').eq('user_id', user.id),
        supabase.from('journal_entries').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(10),
        supabase.from('focus_sessions').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(10)
      ]);

      const completeUserData = {
        tasks: tasksResult.status === 'fulfilled' ? (tasksResult.value.data || []) : [],
        habits: habitsResult.status === 'fulfilled' ? (habitsResult.value.data || []) : [],
        goals: goalsResult.status === 'fulfilled' ? (goalsResult.value.data || []) : [],
        journal_entries: journalResult.status === 'fulfilled' ? (journalResult.value.data || []) : [],
        focus_sessions: focusResult.status === 'fulfilled' ? (focusResult.value.data || []) : [],
        analytics: {
          taskCompletionRate,
          totalFocusTime,
          streakCount,
          habitsCount: habitsData.length,
          focusSessionsCount: focusData.length,
          activityCount: activityData.length
        }
      };

      const { data, error } = await supabase.functions.invoke('gemini-chat-enhanced', {
        body: {
          message: `Analyse en profondeur ces données et calcule un score de productivité détaillé. Retourne UNIQUEMENT un objet JSON avec ces propriétés exactes:
          {
            "score": nombre_0_à_100,
            "level": "Débutant|Intermédiaire|Avancé|Expert|Maître",
            "badges": ["array_de_badges_français_pertinents"],
            "streakBonus": nombre_0_à_20,
            "completionRate": pourcentage_tasks_completed,
            "focusTimeScore": nombre_0_à_25,
            "consistencyScore": nombre_0_à_25,
            "qualityScore": nombre_0_à_25,
            "timeManagementScore": nombre_0_à_25,
            "journalScore": nombre_0_à_15,
            "goalScore": nombre_0_à_15
          }

          BADGES DISPONIBLES (choisis les plus pertinents):
          - "🎯 Organisateur"
          - "⚡ Rapide"
          - "🔥 Persévérant" 
          - "📚 Studieux"
          - "💡 Innovateur"
          - "🏆 Champion"
          - "⏰ Ponctuel"
          - "🎨 Créatif"
          - "🚀 Productif"
          - "💪 Discipliné"
          - "🧘 Zen"
          - "📈 Progressif"
          - "🎉 Motivé"
          - "🏃 Actif"
          - "💎 Excellence"

          Données: ${JSON.stringify(completeUserData)}`,
          user_id: user.id,
          context: {
            user_data: completeUserData,
            recent_messages: []
          }
        }
      });

      if (error) {
        console.error('Error calling AI function:', error);

        // Handle credits exhausted (402)
        if (error.message?.includes('402') || error.message?.includes('credits exhausted') || error.message?.includes('Payment Required')) {
          console.log('AI credits exhausted - using fallback calculation');
          toast.error('💳 Crédits IA épuisés. Ajoutez des crédits dans Settings → Cloud → Usage.');
          calculateFallbackMetrics();
          return;
        }

        // Handle rate limit (429)
        if (error.message?.includes('429') || error.message?.includes('Rate limit')) {
          console.log('Rate limited - using fallback calculation');
          toast.error('🚫 Limite d\'API atteinte. Réessayez plus tard.');
          calculateFallbackMetrics();
          return;
        }

        throw error;
      }

      console.log("AI response received:", data);

      // Try to extract JSON from AI response
      let parsedMetrics = null;
      if (data?.response && !data.error) {
        try {
          // Look for JSON in the response
          const jsonMatch = data.response.match(/\{[\s\S]*\}/);
          if (jsonMatch) {
            parsedMetrics = JSON.parse(jsonMatch[0]);
          }
        } catch (parseError) {
          console.error('Error parsing AI JSON:', parseError);
        }
      }

      if (parsedMetrics && typeof parsedMetrics.score === 'number') {
        console.log("Using AI-calculated metrics:", parsedMetrics);
        setAiMetrics({
          score: Math.max(0, Math.min(100, parsedMetrics.score)),
          level: parsedMetrics.level || 'Débutant',
          badges: Array.isArray(parsedMetrics.badges) ? parsedMetrics.badges : [],
          streakBonus: Math.max(0, Math.min(20, parsedMetrics.streakBonus || 0)),
          completionRate: Math.max(0, Math.min(100, parsedMetrics.completionRate || taskCompletionRate)),
          focusTimeScore: Math.max(0, Math.min(25, parsedMetrics.focusTimeScore || 0)),
          consistencyScore: Math.max(0, Math.min(25, parsedMetrics.consistencyScore || 0)),
          qualityScore: Math.max(0, Math.min(25, parsedMetrics.qualityScore || 0)),
          timeManagementScore: Math.max(0, Math.min(25, parsedMetrics.timeManagementScore || 0)),
          journalScore: Math.max(0, Math.min(15, parsedMetrics.journalScore || 0)),
          goalScore: Math.max(0, Math.min(15, parsedMetrics.goalScore || 0))
        });
      } else {
        console.log("AI response not valid, using fallback calculation");
        calculateFallbackMetrics();
      }

    } catch (error) {
      console.error('Error calculating productivity with AI:', error);
      calculateFallbackMetrics();
    } finally {
      setIsCalculating(false);
    }
  };

  const calculateFallbackMetrics = () => {
    // Calcul de fallback amélioré
    let totalPossibleScore = 0;
    let earnedScore = 0;

    const hasTaskData = taskCompletionRate > 0 || activityData.some(day => day.count > 0);
    if (hasTaskData) {
      const completionScore = Math.min(25, (taskCompletionRate / 100) * 25);
      totalPossibleScore += 25;
      earnedScore += completionScore;
    }

    const hasFocusData = totalFocusTime > 0 || focusData.some(session => session.minutes > 0);
    if (hasFocusData) {
      const avgDailyFocus = totalFocusTime / 7;
      const focusTimeScore = Math.min(25, (avgDailyFocus / 120) * 25);
      totalPossibleScore += 25;
      earnedScore += focusTimeScore;
    }

    const hasHabitsData = habitsData.length > 0;
    if (hasHabitsData) {
      totalPossibleScore += 25;
      earnedScore += Math.min(25, (streakCount / 21) * 25);
    }

    // Score de base
    totalPossibleScore += 25;
    earnedScore += 15; // Score de base pour l'utilisation de l'app

    const totalScore = totalPossibleScore > 0 ? Math.round((earnedScore / totalPossibleScore) * 100) : 0;

    let level = 'Débutant';
    if (totalScore >= 90) level = 'Maître';
    else if (totalScore >= 80) level = 'Expert';
    else if (totalScore >= 65) level = 'Avancé';
    else if (totalScore >= 40) level = 'Intermédiaire';

    const badges = [];
    if (taskCompletionRate >= 80) badges.push('🎯 Organisateur');
    if (totalFocusTime >= 180) badges.push('⚡ Rapide');
    if (streakCount >= 7) badges.push('🔥 Persévérant');
    if (habitsData.length >= 3) badges.push('💪 Discipliné');
    if (totalScore >= 70) badges.push('🚀 Productif');

    setAiMetrics({
      score: totalScore,
      level,
      badges,
      streakBonus: Math.min(10, streakCount / 5),
      completionRate: taskCompletionRate,
      focusTimeScore: hasFocusData ? Math.min(25, (totalFocusTime / 7 / 120) * 25) : 0,
      consistencyScore: hasHabitsData ? Math.min(25, (streakCount / 21) * 25) : 0,
      qualityScore: Math.min(25, totalScore / 4),
      timeManagementScore: Math.min(25, (taskCompletionRate / 100) * 25),
      journalScore: 0,
      goalScore: 0
    });
  };

  return aiMetrics;
};

import { supabase } from "@/integrations/supabase/client";

// Check if user has admin role via database (secure method)
export const isUserAdmin = async (): Promise<boolean> => {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return false;

    const { data } = await supabase
      .from('user_roles')
      .select('role')
      .eq('user_id', user.id)
      .eq('role', 'admin')
      .maybeSingle();

    return !!data;
  } catch (error) {
    console.error('Error checking admin status:', error);
    return false;
  }
};

