          "Content-Type": "application/json",
        },
      }
    );
  }
});

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    // Authenticate user via JWT
    const authHeader = req.headers.get('Authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return new Response(
        JSON.stringify({ error: 'Unauthorized' }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 401 }
      );
    }

    const supabaseAuth = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_ANON_KEY') ?? '',
      { global: { headers: { Authorization: authHeader } } }
    );

    const token = authHeader.replace('Bearer ', '');
    const { data: claimsData, error: claimsError } = await supabaseAuth.auth.getUser(token);

    if (claimsError || !claimsData?.user?.id) {
      console.error('Authentication failed:', claimsError);
      return new Response(
        JSON.stringify({ error: 'Invalid token' }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 401 }
      );
    }

    const authenticatedUserId = claimsData.user.id;

    const { message, context } = await req.json();

    console.log('Received request:', { message: message?.substring(0, 100), userId: authenticatedUserId, hasContext: !!context });

    // Get Lovable API key (uses Gemini under the hood)
    const LOVABLE_API_KEY = Deno.env.get('LOVABLE_API_KEY');
    if (!LOVABLE_API_KEY) {
      console.error('LOVABLE_API_KEY not found');
      return new Response(
        JSON.stringify({ error: 'AI service not configured' }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 500 }
      );
    }

    // Create Supabase client with service role for database operations
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    // Check if user is premium or admin
    let isPremium = false;
    try {
      const { data: subscriptionData } = await supabaseClient
        .from('subscribers')
        .select('subscribed')
        .eq('user_id', authenticatedUserId)
        .maybeSingle();

      const { data: adminRole } = await supabaseClient
        .from('user_roles')
        .select('role')
        .eq('user_id', authenticatedUserId)
        .eq('role', 'admin')
        .maybeSingle();

      isPremium = subscriptionData?.subscribed === true || !!adminRole;
    } catch (error) {
      console.error("Error checking subscription status:", error);
    }

    // If user is not premium, check request limits and AI credits
    if (!isPremium) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      const { count, error } = await supabaseClient
        .from('ai_requests')
        .select('*', { count: 'exact', head: false })
        .eq('service', 'gemini-chat-enhanced')
        .eq('user_id', authenticatedUserId)
        .gte('created_at', today.toISOString());

      if (error) {
        console.error("Error checking AI request limit:", error);
      }

      const requestsToday = count || 0;
      const BASE_FREE_REQUESTS = 5;

      // Check AI credits (25 credits = 1 extra request)
      const { data: aiCreditsData } = await supabaseClient
        .from('ai_credits')
        .select('credits')
        .eq('user_id', authenticatedUserId)
        .maybeSingle();

      const aiCredits = aiCreditsData?.credits || 0;
      const bonusRequests = Math.floor(aiCredits / 25);
      const totalAllowedRequests = BASE_FREE_REQUESTS + bonusRequests;

      if (requestsToday >= BASE_FREE_REQUESTS) {
        if (bonusRequests > 0 && requestsToday < totalAllowedRequests) {
          // Deduct 25 credits for this extra request
          const newCredits = aiCredits - 25;
          await supabaseClient
            .from('ai_credits')
            .update({ credits: newCredits, last_updated: new Date().toISOString() })
            .eq('user_id', authenticatedUserId);

          console.log(`Used 25 AI credits for bonus request. Credits remaining: ${newCredits}`);
        } else if (requestsToday >= totalAllowedRequests) {
          return new Response(
            JSON.stringify({ 
              error: 'AI_LIMIT_REACHED',
              response: `⚠️ **Limite atteinte**\n\nVous avez atteint votre limite de ${BASE_FREE_REQUESTS} requêtes quotidiennes gratuites${bonusRequests > 0 ? ` + ${bonusRequests} requêtes bonus (crédits IA épuisés)` : ''}. Achetez des crédits IA dans la boutique (25 crédits = 1 requête) ou passez à premium.`
            }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
          );
        }
      }
    }

    // Déterminer le mode de conversation
    const analysisMode = context?.analysis_mode || message.includes('[MODE ANALYSE');
    const creationMode = context?.creation_mode || message.includes('[MODE CRÉATION');
    const messageContext = context?.message_context || 'conversation normale';

    // Système de prompts adaptatif selon le mode
    let systemPrompt = '';

    if (analysisMode) {
      systemPrompt = `Tu es un expert en analyse de données de productivité et développement personnel pour DeepFlow.

MISSION PRINCIPALE: Analyser les données utilisateur de manière approfondie et fournir des insights personnalisés, détaillés et actionables.

POUR LES ANALYSES APPROFONDIES:
- Examine minutieusement tous les patterns et tendances dans les données
- Calcule des métriques avancées et des corrélations
- Identifie les forces spécifiques et les faiblesses précises
- Fournis des observations perspicaces basées sur les données réelles
- Propose des recommandations concrètes, personnalisées et réalisables
- Utilise des comparaisons temporelles et des benchmarks
- Identifie des opportunités d'optimisation cachées

STYLE DE RÉPONSE:
- Analytique et factuel
- Utilise des données chiffrées pour étayer tes analyses
- Structure tes réponses avec des sections claires
- Donne des insights surprenants mais fondés
- Propose des actions concrètes avec des délais
- Utilise des métaphores ou comparaisons pour clarifier
- RÉPONDS DE MANIÈRE COMPLÈTE - ne coupe jamais ta réponse

DONNÉES UTILISATEUR DISPONIBLES: ${JSON.stringify(context?.user_data || {})}

Sois un véritable analyste de données personnelles, perspicace et utile.`;

    } else if (creationMode) {
      systemPrompt = `Tu es un assistant IA spécialisé dans la productivité pour DeepFlow, en MODE CRÉATION.

RÈGLES POUR LE MODE CRÉATION:
- L'utilisateur VEUT que tu puisses suggérer des créations
- Propose des créations pertinentes basées sur ses demandes explicites
- Analyse ses besoins et suggère des tâches, habitudes ou objectifs appropriés
- Sois proactif dans tes suggestions quand c'est demandé
- Explique pourquoi tu suggères chaque création

Format de réponse avec suggestion:
{
  "response": "ta réponse conversationnelle normale",
  "suggestion": {
    "type": "task|habit|goal",
    "title": "titre suggéré",
    "description": "description suggérée",
    "priority": "high|medium|low" (pour tâches),
    "frequency": "daily|weekly|monthly" (pour habitudes),
    "category": "catégorie suggérée" (pour objectifs),
    "reasoning": "pourquoi tu suggères cela basé sur ses données"
  }
}

DONNÉES UTILISATEUR: ${JSON.stringify(context?.user_data || {})}

Tu es en mode création - aide l'utilisateur à créer ce dont il a besoin !`;

    } else {
      systemPrompt = `Tu es un assistant IA spécialisé dans la productivité pour DeepFlow, en MODE DISCUSSION.

MISSION: Être un conseiller en productivité bienveillant et expert.

RÈGLES STRICTES:
- NE SUGGÈRE PAS de créations automatiquement
- Concentre-toi sur les conseils, l'analyse et la discussion
- Réponds aux questions de manière approfondie ET COMPLÈTE
- Partage des techniques et méthodes de productivité
- Aide à résoudre des problèmes spécifiques
- Donne des insights sur les données existantes
- NE COUPE JAMAIS TA RÉPONSE - termine toujours tes phrases

STYLE:
- Conversationnel et bienveillant
- Expert mais accessible  
- Motivant et encourageant
- Basé sur les meilleures pratiques de productivité

DONNÉES UTILISATEUR: ${JSON.stringify(context?.user_data || {})}

Tu es en mode discussion - concentre-toi sur les conseils et l'analyse sans suggestions de création.`;
    }

    // Prepare recent messages for context
    const recentMessages = (context?.recent_messages || []).slice(-10);

    console.log('Making request to Lovable AI Gateway (Gemini) with mode:', messageContext);

    // Build messages array for the API
    const messages = [
      { role: 'system', content: systemPrompt },
      ...recentMessages.map((msg: any) => ({
        role: msg.role === 'assistant' ? 'assistant' : 'user',
        content: msg.content
      })),
      { role: 'user', content: message }
    ];

    // Call Lovable AI Gateway (which uses Gemini)
    const aiResponse = await fetch('https://ai.gateway.lovable.dev/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${LOVABLE_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'google/gemini-2.5-flash',
        messages: messages,
        max_tokens: 8192,
        temperature: 0.7,
      }),
    });

    if (!aiResponse.ok) {
      if (aiResponse.status === 429) {
        return new Response(
          JSON.stringify({ error: 'Rate limit exceeded. Please try again later.' }),
          { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 429 }
        );
      }
      if (aiResponse.status === 402) {
        return new Response(
          JSON.stringify({ error: 'AI credits exhausted. Please add credits to your Lovable workspace.' }),
          { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 402 }
        );
      }
      const errorText = await aiResponse.text();
      console.error('Lovable AI error:', aiResponse.status, errorText);
      throw new Error(`AI gateway error: ${errorText}`);
    }

    const aiData = await aiResponse.json();
    let responseText = aiData.choices?.[0]?.message?.content || '';

    console.log('AI response received, length:', responseText.length);

    // Try to parse JSON response
    let suggestion = null;
    let isJsonResponse = false;

    // Check if response is pure JSON (for insights, etc.)
    try {
      const jsonBlockMatch = responseText.match(/```json\s*([\s\S]*?)```/);
      if (jsonBlockMatch) {
        const jsonContent = jsonBlockMatch[1].trim();
        JSON.parse(jsonContent);
        responseText = jsonContent;
        isJsonResponse = true;
      }
    } catch (e) {
      // Not a pure JSON response, continue with normal parsing
    }

    // Only clean up if it's not a pure JSON response
    if (!isJsonResponse) {
      if (creationMode) {
        try {
          const jsonMatch = responseText.match(/\{[\s\S]*\}/);
          if (jsonMatch) {
            const parsed = JSON.parse(jsonMatch[0]);
            if (parsed.suggestion) {
              suggestion = parsed.suggestion;
              responseText = parsed.response || responseText;
            }
          }
        } catch (e) {
          console.log('No JSON suggestion found in response');
        }
      }

      // Clean up response for better readability
      responseText = responseText
        .replace(/```json[\s\S]*?```/g, "")
        .replace(/\{[\s\S]*?"suggestion"[\s\S]*?\}/g, "")
        .trim();
    }

    // Log AI request
    await supabaseClient.from('ai_requests').insert({
      user_id: authenticatedUserId,
      service: 'gemini-chat-enhanced'
    });

    console.log('Returning response:', { 
      responseLength: responseText.length, 
      hasSuggestion: !!suggestion,
      mode: messageContext 
    });

    return new Response(
      JSON.stringify({ 
        response: responseText,
        suggestion: suggestion,
        mode: messageContext
      }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );

  } catch (error) {
    console.error('Error in gemini-chat-enhanced:', error);
    return new Response(
      JSON.stringify({ error: 'Une erreur interne est survenue.' }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 500 }
    );
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

const PAYPAL_CLIENT_ID = Deno.env.get("PAYPAL_CLIENT_ID")!;
const PAYPAL_CLIENT_SECRET = Deno.env.get("PAYPAL_CLIENT_SECRET")!;
const PAYPAL_API_URL = "https://api-m.sandbox.paypal.com"; // Use sandbox for testing

async function getPayPalAccessToken(): Promise<string> {
  const auth = btoa(`${PAYPAL_CLIENT_ID}:${PAYPAL_CLIENT_SECRET}`);

  const response = await fetch(`${PAYPAL_API_URL}/v1/oauth2/token`, {
    method: "POST",
    headers: {
      "Authorization": `Basic ${auth}`,
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: "grant_type=client_credentials",
  });

  if (!response.ok) {
    const error = await response.text();
    console.error("PayPal auth error:", error);
    throw new Error("Failed to get PayPal access token");
  }

  const data = await response.json();
  return data.access_token;
}

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("Authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "No authorization header" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const supabase = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_ANON_KEY")!,
      { global: { headers: { Authorization: authHeader } } }
    );

    const { data: { user }, error: userError } = await supabase.auth.getUser();
    if (userError || !user) {
      return new Response(JSON.stringify({ error: "User not authenticated" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const { plan } = await req.json();

    // Define pricing for plans - Updated to 4.99€
    const prices: Record<string, { amount: string; tier: string }> = {
      premium_monthly: { amount: "4.99", tier: "premium" },
      premium_yearly: { amount: "49.99", tier: "premium" },
    };

    const selectedPlan = prices[plan];
    if (!selectedPlan) {
      return new Response(JSON.stringify({ error: "Invalid plan" }), {
        status: 400,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const accessToken = await getPayPalAccessToken();

    // Create PayPal order
    const orderResponse = await fetch(`${PAYPAL_API_URL}/v2/checkout/orders`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${accessToken}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        intent: "CAPTURE",
        purchase_units: [
          {
            amount: {
              currency_code: "EUR",
              value: selectedPlan.amount,
            },
            description: `DeepFlow ${selectedPlan.tier.charAt(0).toUpperCase() + selectedPlan.tier.slice(1)} Subscription`,
          },
        ],
        application_context: {
          brand_name: "DeepFlow",
          landing_page: "NO_PREFERENCE",
          user_action: "PAY_NOW",
          return_url: `${req.headers.get("origin")}/settings?payment=success`,
          cancel_url: `${req.headers.get("origin")}/settings?payment=cancelled`,
        },
      }),
    });

    if (!orderResponse.ok) {
      const error = await orderResponse.text();
      console.error("PayPal order creation error:", error);
      return new Response(JSON.stringify({ error: "Failed to create PayPal order" }), {
        status: 500,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const orderData = await orderResponse.json();

    // Store pending payment in database
    const supabaseAdmin = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!
    );

    await supabaseAdmin.from("paypal_payments").insert({
      user_id: user.id,
      paypal_order_id: orderData.id,
      amount: parseFloat(selectedPlan.amount),
      currency: "EUR",
      status: "pending",
      subscription_tier: selectedPlan.tier,
    });

    console.log(`PayPal order created: ${orderData.id} for user ${user.id}`);

    return new Response(JSON.stringify({ 
      orderId: orderData.id,
      approvalUrl: orderData.links.find((l: any) => l.rel === "approve")?.href,
    }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error) {
    console.error("Error creating PayPal order:", error);
    return new Response(JSON.stringify({ error: error.message }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

